insert into public.ai_animations (lesson_id,tipo,status,model,custo_usd,roteiro,urls) values ('10c00000-b551-4c00-9000-0000000b0002','interactive','ready','handcrafted-interactive',0,'{"titulo":"Simulador — Mistura de Cor (RGBW + Dimmer)","metadata":{"titulo_aula":"Simulador — Mistura de Cor (RGBW + Dimmer)","total_cenas":1,"duracao_total":0,"abordagem_didatica":"Simulador interativo — pratique movendo os controles"},"cenas":[{"numero":1,"titulo":"Simulador — Mistura de Cor (RGBW + Dimmer)","modo":"widget","narracao":"Some vermelho, verde e azul para criar qualquer cor e use o dimmer para a intensidade. Complete as 5 missões.","explicacao_texto":"Some vermelho, verde e azul para criar qualquer cor e use o dimmer para a intensidade. Complete as 5 missões.","destaques":["Mistura aditiva RGB → luz","Canal W (branco) para pastéis e brancos limpos","Dimmer = intensidade","R+G+B no máximo = branco"]}]}'::jsonb,'[{"html":"<!doctype html><html lang=\"pt-BR\"><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no\">\r\n<title>Simulador — Mistura de Cor (RGBW + Dimmer)</title>\r\n<style>\r\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\r\nhtml,body{height:100%;background:#0b0e14;color:#e7ecf3;font-family:system-ui,Segoe UI,Roboto,Arial,sans-serif;overflow:hidden}\r\nbody{display:flex;align-items:center;justify-content:center}\r\n.console{width:1000px;height:620px;background:linear-gradient(180deg,#121722,#0d111a);border:1px solid #223049;border-radius:14px;padding:18px;display:grid;grid-template-columns:1.15fr .85fr;gap:16px;box-shadow:0 10px 40px #0008}\r\n.stage{position:relative;background:#05070c;border:1px solid #1c2740;border-radius:12px;overflow:hidden;display:flex;flex-direction:column}\r\n.stage canvas{width:100%;height:100%;display:block}\r\n.panel{display:flex;flex-direction:column;gap:12px;min-width:0}\r\nh1{font-size:15px;font-weight:700;letter-spacing:.2px;color:#cfe0ff}\r\n.sub{font-size:11.5px;color:#8aa0c2;line-height:1.45}\r\n.faders{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;flex:1;align-items:end}\r\n.fad{display:flex;flex-direction:column;align-items:center;gap:6px;height:100%;justify-content:end}\r\n.track{position:relative;width:34px;flex:1;min-height:150px;background:#0c1220;border:1px solid #263449;border-radius:8px;touch-action:none;cursor:pointer}\r\n.fill{position:absolute;left:0;right:0;bottom:0;border-radius:0 0 7px 7px}\r\n.knob{position:absolute;left:-3px;right:-3px;height:16px;background:#e7ecf3;border-radius:5px;box-shadow:0 2px 6px #000a;transform:translateY(8px)}\r\n.lbl{font-size:11px;font-weight:700}.val{font-size:11px;color:#9fb4d6;font-variant-numeric:tabular-nums}\r\n.swatch{height:38px;border-radius:8px;border:1px solid #2a3a55}\r\n.mission{background:#0e1626;border:1px solid #24406e;border-radius:10px;padding:10px 12px;font-size:12px;line-height:1.5}\r\n.mission b{color:#8fd0ff}\r\n.mrow{display:flex;align-items:center;gap:8px;margin-top:4px}\r\n.dot{width:14px;height:14px;border-radius:50%;border:2px solid #37507a;flex:none}\r\n.dot.ok{background:#39d98a;border-color:#39d98a}\r\n.btns{display:flex;gap:8px;flex-wrap:wrap}\r\nbutton{background:#1b2740;color:#dce7fb;border:1px solid #33507f;border-radius:8px;padding:7px 11px;font-size:12px;font-weight:600;cursor:pointer}\r\nbutton:hover{background:#233459}\r\n.tag{display:inline-block;font-size:10px;padding:2px 7px;border-radius:999px;background:#16233c;border:1px solid #294066;color:#9db6df;margin-left:6px}\r\n.hint{font-size:11px;color:#7f96bb}\r\n</style></head>\r\n<body>\r\n<div class=\"console\" id=\"console\">\r\n  <div class=\"stage\"><canvas id=\"cv\"></canvas></div>\r\n  <div class=\"panel\">\r\n    <div><h1>Mistura de Cor no Refletor LED <span class=\"tag\" id=\"ftype\">RGBW</span></h1>\r\n      <div class=\"sub\">Arraste os faders. No LED a cor é <b>aditiva</b>: some Vermelho + Verde + Azul. O <b>Dimmer</b> controla a intensidade geral; o <b>W</b> (branco) limpa e clareia.</div></div>\r\n    <div class=\"faders\" id=\"faders\"></div>\r\n    <div class=\"swatch\" id=\"swatch\"></div>\r\n    <div class=\"mission\" id=\"mission\"></div>\r\n    <div class=\"btns\">\r\n      <button id=\"toggleW\">Modo: RGBW</button>\r\n      <button id=\"reset\">Zerar</button>\r\n      <button id=\"next\">Próxima missão ▸</button>\r\n    </div>\r\n    <div class=\"hint\" id=\"hint\">Dica: R+G+B nos três = branco (mas “sujo”). Use o canal W para um branco limpo.</div>\r\n  </div>\r\n</div>\r\n<script>\r\nconst CH=[{k:''d'',lbl:''DIM'',c:''#e7ecf3'',v:0},{k:''r'',lbl:''R'',c:''#ff4d4d'',v:0},{k:''g'',lbl:''G'',c:''#48e06a'',v:0},{k:''b'',lbl:''B'',c:''#4d8bff'',v:0},{k:''w'',lbl:''W'',c:''#fff7e6'',v:0}];\r\nconst st={d:0,r:0,g:0,b:0,w:0};\r\nlet rgbwMode=true;\r\nconst fadersEl=document.getElementById(''faders'');\r\nCH.forEach(ch=>{\r\n  const el=document.createElement(''div'');el.className=''fad'';el.dataset.k=ch.k;\r\n  el.innerHTML=`<div class=\"val\" data-v>0</div><div class=\"track\"><div class=\"fill\" style=\"background:${ch.c};height:0%\"></div><div class=\"knob\" style=\"bottom:0%\"></div></div><div class=\"lbl\" style=\"color:${ch.c}\">${ch.lbl}</div>`;\r\n  fadersEl.appendChild(el);\r\n  const track=el.querySelector(''.track'');\r\n  const set=(cy)=>{const r=track.getBoundingClientRect();let p=1-(cy-r.top)/r.height;p=Math.max(0,Math.min(1,p));st[ch.k]=Math.round(p*255);render();};\r\n  track.addEventListener(''pointerdown'',e=>{try{track.setPointerCapture(e.pointerId);}catch(_){}set(e.clientY);});\r\n  track.addEventListener(''pointermove'',e=>{if(e.buttons)set(e.clientY);});\r\n});\r\nfunction currentColor(){\r\n  // aditiva: base RGB, mais W soma um branco; dimmer escala tudo\r\n  let r=st.r,g=st.g,b=st.b;\r\n  if(rgbwMode){r=Math.min(255,r+st.w);g=Math.min(255,g+st.w);b=Math.min(255,b+st.w);}\r\n  const dim=st.d/255;\r\n  return {r:Math.round(r*dim),g:Math.round(g*dim),b:Math.round(b*dim),dim};\r\n}\r\nconst cv=document.getElementById(''cv'');const ctx=cv.getContext(''2d'');\r\nfunction sizeCanvas(){const r=cv.getBoundingClientRect();const dpr=Math.min(2,devicePixelRatio||1);cv.width=r.width*dpr;cv.height=r.height*dpr;ctx.setTransform(dpr,0,0,dpr,0,0);drawStage();}\r\nfunction drawStage(){\r\n  const r=cv.getBoundingClientRect();const W=r.width,H=r.height;\r\n  ctx.clearRect(0,0,W,H);\r\n  // fundo palco\r\n  ctx.fillStyle=''#05070c'';ctx.fillRect(0,0,W,H);\r\n  const col=currentColor();const cx=W*0.5, topY=H*0.13, fixW=Math.min(120,W*0.22);\r\n  // luminária\r\n  ctx.fillStyle=''#161b26'';ctx.fillRect(cx-fixW/2,topY-18,fixW,20);\r\n  ctx.fillStyle=''#0f131c'';ctx.fillRect(cx-fixW/2+6,topY,fixW-12,10);\r\n  // facho (cone)\r\n  const beamBottom=H*0.9, spread=W*0.34;\r\n  const g=ctx.createLinearGradient(0,topY,0,beamBottom);\r\n  const a=0.06+0.5*(col.dim);\r\n  g.addColorStop(0,`rgba(${col.r},${col.g},${col.b},${Math.min(0.95,a+0.15)})`);\r\n  g.addColorStop(1,`rgba(${col.r},${col.g},${col.b},0)`);\r\n  ctx.beginPath();ctx.moveTo(cx-fixW*0.28,topY+4);ctx.lineTo(cx-spread,beamBottom);ctx.lineTo(cx+spread,beamBottom);ctx.lineTo(cx+fixW*0.28,topY+4);ctx.closePath();\r\n  ctx.fillStyle=g;ctx.fill();\r\n  // pool de luz no chão\r\n  const pool=ctx.createRadialGradient(cx,beamBottom,4,cx,beamBottom,spread*0.95);\r\n  pool.addColorStop(0,`rgba(${col.r},${col.g},${col.b},${Math.min(0.9,a+0.2)})`);\r\n  pool.addColorStop(1,`rgba(${col.r},${col.g},${col.b},0)`);\r\n  ctx.fillStyle=pool;ctx.beginPath();ctx.ellipse(cx,beamBottom,spread*0.95,spread*0.22,0,0,7);ctx.fill();\r\n  // artista (silhueta) que recebe a cor\r\n  const px=cx,py=beamBottom-6;\r\n  ctx.save();\r\n  const lit=col.dim>0.02;\r\n  const bodyCol=lit?`rgb(${Math.round(col.r*0.7+20)},${Math.round(col.g*0.7+20)},${Math.round(col.b*0.7+20)})`:''#1a2030'';\r\n  ctx.fillStyle=bodyCol;\r\n  ctx.beginPath();ctx.ellipse(px,py-70,14,16,0,0,7);ctx.fill(); //cabeça\r\n  ctx.beginPath();ctx.moveTo(px-18,py);ctx.lineTo(px-12,py-52);ctx.lineTo(px+12,py-52);ctx.lineTo(px+18,py);ctx.closePath();ctx.fill();//corpo\r\n  ctx.restore();\r\n  // leitura DMX\r\n  ctx.fillStyle=''#7f96bb'';ctx.font=''11px system-ui'';\r\n  ctx.fillText(`DMX  DIM:${st.d}  R:${st.r}  G:${st.g}  B:${st.b}`+(rgbwMode?`  W:${st.w}`:''''),12,H-14);\r\n}\r\nfunction render(){\r\n  CH.forEach(ch=>{const el=fadersEl.querySelector(`[data-k=\"${ch.k}\"]`);const v=st[ch.k];const p=v/255*100;\r\n    el.querySelector(''.fill'').style.height=p+''%'';el.querySelector(''.knob'').style.bottom=p+''%'';el.querySelector(''[data-v]'').textContent=v;});\r\n  const c=currentColor();document.getElementById(''swatch'').style.background=`rgb(${c.r},${c.g},${c.b})`;\r\n  drawStage();checkMission();\r\n}\r\n// ── Missões ──\r\nconst MISSIONS=[\r\n  {t:''Faça a luz acender em <b>vermelho puro</b>.'',ok:()=>st.d>200&&st.r>200&&st.g<40&&st.b<40&&st.w<40},\r\n  {t:''Some Vermelho + Verde para obter <b>amarelo</b>.'',ok:()=>st.d>180&&st.r>180&&st.g>180&&st.b<50},\r\n  {t:''Some Vermelho + Azul para obter <b>magenta</b>.'',ok:()=>st.d>180&&st.r>180&&st.b>180&&st.g<60},\r\n  {t:''Faça <b>branco</b> — dica: use o canal <b>W</b> (mude para modo RGBW se preciso) ou os três RGB no máximo.'',ok:()=>{const c=currentColor();return c.dim>0.7&&c.r>200&&c.g>200&&c.b>200;}},\r\n  {t:''Deixe a cor e <b>abaixe o Dimmer para ~50%</b> (fade sem mudar a cor).'',ok:()=>st.d>=110&&st.d<=145&&(st.r+st.g+st.b+st.w>150)},\r\n];\r\nlet mi=0;\r\nfunction drawMission(){const m=MISSIONS[mi];document.getElementById(''mission'').innerHTML=\r\n  `<div><b>Missão ${mi+1}/${MISSIONS.length}:</b> ${m.t}</div><div class=\"mrow\"><span class=\"dot\" id=\"mdot\"></span><span id=\"mstat\">Ajuste os faders…</span></div>`;}\r\nfunction checkMission(){const m=MISSIONS[mi];const dot=document.getElementById(''mdot'');const stat=document.getElementById(''mstat'');if(!dot)return;\r\n  if(m.ok()){dot.classList.add(''ok'');stat.textContent=''✓ Conseguiu! Toque em “Próxima missão”.'';}\r\n  else{dot.classList.remove(''ok'');stat.textContent=''Ajuste os faders…'';}}\r\ndocument.getElementById(''next'').onclick=()=>{mi=(mi+1)%MISSIONS.length;drawMission();render();};\r\ndocument.getElementById(''reset'').onclick=()=>{st.d=st.r=st.g=st.b=st.w=0;render();};\r\ndocument.getElementById(''toggleW'').onclick=(e)=>{rgbwMode=!rgbwMode;e.target.textContent=''Modo: ''+(rgbwMode?''RGBW'':''RGB'');document.getElementById(''ftype'').textContent=rgbwMode?''RGBW'':''RGB'';render();};\r\n// ── Fit responsivo ──\r\nfunction fit(){const DW=1000,DH=620;const vw=innerWidth,vh=innerHeight;const scrH=(window.screen&&screen.height)||vh;const iframeTaller=vh>scrH+8;const visH=Math.min(vh,scrH);const headerAllow=iframeTaller?84:(vh>700?24:6);const effVh=Math.max(240,visH-headerAllow);const z=Math.min(vw/DW,effVh/DH);document.getElementById(''console'').style.zoom=z;requestAnimationFrame(sizeCanvas);}\r\naddEventListener(''resize'',fit);\r\ndrawMission();render();fit();setTimeout(fit,60);\r\n</script></body></html>\r\n"}]'::jsonb);

-- AULA 3 [M1.3]: Tipos de refletores: dos convencionais aos moving heads
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('10c00000-b551-4c00-9000-0000000b0003','10c00000-b551-4c00-9000-0000000000a1','Tipos de refletores: dos convencionais aos moving heads','texto','<p><strong>Cada refletor foi feito para uma função — e escolher o errado é queimar dinheiro e trabalho.</strong> Um PAR nunca vai recortar uma logo, e um beam nunca vai dar um banho suave. Nesta aula você aprende a reconhecer as famílias de fixture, do convencional fixo ao moving head motorizado, e a saber na hora qual pedir para cada tarefa.</p>

<h3>Convencionais (fixos)</h3>
<p>São refletores sem motor: você aponta na mão, prende na truss e ele fica ali. Simples, robustos e baratos por ponto.</p>

<figure style="margin:16px 0;text-align:center"><img src="https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/img-luz-basico/par-led.jpg" alt="Refletores PAR de LED alinhados, cada um com uma matriz de LEDs coloridos (vermelho, verde, azul, branco) na frente." style="max-width:100%;border-radius:10px;border:1px solid rgba(0,0,0,.12)" /><figcaption style="font-size:12px;opacity:.75;margin-top:6px">O PAR LED — o ''cavalo de batalha'' do banho de cor: uma matriz de LEDs RGBW num corpo compacto de alumínio.</figcaption></figure>

<ul>
<li><strong>PAR (PAR64 / PAR LED):</strong> o <em>cavalo de batalha</em>. Dá um <strong>banho de cor</strong> forte, facho fixo, <strong>sem foco</strong> nem borda definida. O PAR64 usa lâmpada + dimmer externo; o PAR LED já mistura cor sozinho (RGB/RGBW). Serve para bater cor em palco, banda, cenário.</li>
<li><strong>Fresnel:</strong> lente que espalha a luz e entrega uma <strong>borda suave</strong>, difusa. O facho é <strong>ajustável</strong> (spot/flood) aproximando ou afastando a lâmpada da lente. Muito usado em <strong>teatro e TV</strong> por misturar bem com os vizinhos.</li>
<li><strong>Elipsoidal / ERS / recorte (tipo Source Four):</strong> o <strong>canhão de recorte</strong>. Facho <strong>preciso</strong>, com <strong>facas/shutters</strong> para cortar a luz em linha reta, <strong>porta-gobo</strong> (projeta desenhos e logos) e <strong>íris</strong> (fecha o círculo). É o que recorta cenário e projeta a marca no fundo.</li>
<li><strong>Ribalta / barra LED / batten:</strong> barra com vários LEDs em linha, para banhar do chão para cima ou marcar linhas.</li>
<li><strong>Ciclorama / CYC:</strong> refletor de facho largo e uniforme feito para <strong>banhar o fundo e o telão</strong> com cor cheia, sem manchas.</li>
</ul>

<figure style="margin:16px 0;text-align:center"><img src="https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/img-luz-basico/elipsoidal-fresnel.jpg" alt="Dois refletores convencionais de teatro: à esquerda um elipsoidal (recorte) com facas de corte; à direita um fresnel com a lente de anéis concêntricos." style="max-width:100%;border-radius:10px;border:1px solid rgba(0,0,0,.12)" /><figcaption style="font-size:12px;opacity:.75;margin-top:6px">Convencionais de teatro: o elipsoidal/recorte (esquerda, com as facas de corte e porta-gobo) e o fresnel (direita, com a lente de anéis que suaviza a borda).</figcaption></figure>

<h3>Moving heads (motorizados: pan/tilt)</h3>
<p>Movings giram (<strong>pan</strong>, horizontal) e inclinam (<strong>tilt</strong>, vertical) por motor, e trocam cor, gobo e foco pelo DMX. Um moving faz o trabalho de vários convencionais — mas custa mais e pede manutenção. As três famílias principais:</p>

<figure style="margin:16px 0;text-align:center"><img src="https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/img-luz-basico/moving-heads.jpg" alt="Três moving heads profissionais lado a lado: um wash de lente grande, um spot e um beam de lente pequena, sobre suas bases." style="max-width:100%;border-radius:10px;border:1px solid rgba(0,0,0,.12)" /><figcaption style="font-size:12px;opacity:.75;margin-top:6px">Moving heads: da esquerda para a direita, o wash (lente grande, banho), o spot (recorte com gobo) e o beam (facho estreito e denso).</figcaption></figure>

<table>
<tr><th>Tipo</th><th>Facho</th><th>Recursos típicos</th><th>Serve para</th></tr>
<tr><td><strong>SPOT</strong></td><td>Definido, médio</td><td>Roda de gobos, íris, foco, prisma, CMY</td><td>Recortar e projetar gobos, logos e texturas</td></tr>
<tr><td><strong>BEAM</strong></td><td>MUITO estreito e denso</td><td>Pouca abertura, cor saturada, prisma</td><td>Risca de luz no ar; ótimo com fumaça — o "canhão"/tubo</td></tr>
<tr><td><strong>WASH</strong></td><td>Largo e suave, sem borda</td><td>Zoom, mistura de cor (RGBW/CMY)</td><td>Banho de cor amplo em palco e plateia</td></tr>
<tr><td><strong>HÍBRIDO</strong></td><td>Variável (fecha e abre)</td><td>Spot + beam + wash na mesma fixture</td><td>Fazer os três papéis quando falta ponto/grana</td></tr>
</table>

<h3>Efeito</h3>
<p>Fixtures dedicadas a impacto, não a iluminar:</p>
<ul>
<li><strong>Strobe:</strong> flashes brancos rápidos, cortam o movimento e explodem o refrão.</li>
<li><strong>Blinder:</strong> várias lâmpadas quentes viradas para a <strong>plateia</strong>, para cegar e levantar o público.</li>
<li><strong>Atomic:</strong> strobe potente, muitas vezes com faixa de LED de cor em volta.</li>
<li><strong>Laser:</strong> feixe coerente, tratado <em>à parte</em> (tem norma e segurança próprias).</li>
<li><strong>Matrix / pixel:</strong> LEDs em grade, controlados individualmente para formar desenhos, textos e animações.</li>
</ul>

<h3>Resumo prático</h3>
<p><strong>WASH pinta, SPOT desenha, BEAM risca o ar.</strong> Nos convencionais: PAR dá banho, Fresnel dá borda suave, elipsoidal recorta e projeta, CYC banha o fundo. Antes de pedir uma fixture, defina a função — pintar cor, recortar/projetar ou fazer feixe no ar — e o resto se escolhe sozinho.</p>',20,3,true,false);
