insert into public.ai_animations (lesson_id,tipo,status,model,custo_usd,roteiro,urls) values ('10c00000-b551-4c00-9000-0000000b0004','interactive','ready','handcrafted-interactive',0,'{"titulo":"Simulador — Iluminação de 3 Pontos","metadata":{"titulo_aula":"Simulador — Iluminação de 3 Pontos","total_cenas":1,"duracao_total":0,"abordagem_didatica":"Simulador interativo — pratique movendo os controles"},"cenas":[{"numero":1,"titulo":"Simulador — Iluminação de 3 Pontos","modo":"widget","narracao":"Acenda key, fill e contraluz e veja o artista ganhar volume. Complete as 4 missões.","explicacao_texto":"Acenda key, fill e contraluz e veja o artista ganhar volume. Complete as 4 missões.","destaques":["Key = luz principal","Fill = suaviza a sombra","Contraluz = separa do fundo","Só contraluz = silhueta"]}]}'::jsonb,'[{"html":"<!doctype html><html lang=\"pt-BR\"><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no\">\r\n<title>Simulador — Iluminação de 3 Pontos</title>\r\n<style>\r\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\r\nhtml,body{height:100%;background:#0b0e14;color:#e7ecf3;font-family:system-ui,Segoe UI,Roboto,Arial,sans-serif;overflow:hidden}\r\nbody{display:flex;align-items:center;justify-content:center}\r\n.console{width:1000px;height:620px;background:linear-gradient(180deg,#121722,#0d111a);border:1px solid #223049;border-radius:14px;padding:18px;display:grid;grid-template-columns:1.2fr .8fr;gap:16px;box-shadow:0 10px 40px #0008}\r\n.stage{position:relative;background:#04060a;border:1px solid #1c2740;border-radius:12px;overflow:hidden}\r\n.stage canvas{width:100%;height:100%;display:block}\r\n.panel{display:flex;flex-direction:column;gap:11px;min-width:0}\r\nh1{font-size:15px;font-weight:700;color:#cfe0ff}\r\n.sub{font-size:11.5px;color:#8aa0c2;line-height:1.45}\r\n.lamp{display:flex;align-items:center;gap:10px;background:#0e1421;border:1px solid #22314c;border-radius:9px;padding:8px 10px}\r\n.lamp .sw{width:40px;height:22px;border-radius:999px;background:#2a3550;position:relative;flex:none;cursor:pointer;transition:.15s}\r\n.lamp .sw.on{background:#39d98a}\r\n.lamp .sw i{position:absolute;top:2px;left:2px;width:18px;height:18px;border-radius:50%;background:#fff;transition:.15s}\r\n.lamp .sw.on i{left:20px}\r\n.lamp .nm{font-size:12px;font-weight:700;flex:none;width:74px}\r\n.lamp .desc{font-size:10.5px;color:#8298bd;flex:1;line-height:1.3}\r\n.lamp input[type=range]{width:80px}\r\n.mission{background:#0e1626;border:1px solid #24406e;border-radius:10px;padding:10px 12px;font-size:12px;line-height:1.5}\r\n.mrow{display:flex;align-items:center;gap:8px;margin-top:4px}\r\n.dot{width:14px;height:14px;border-radius:50%;border:2px solid #37507a;flex:none}.dot.ok{background:#39d98a;border-color:#39d98a}\r\n.btns{display:flex;gap:8px}\r\nbutton{background:#1b2740;color:#dce7fb;border:1px solid #33507f;border-radius:8px;padding:7px 11px;font-size:12px;font-weight:600;cursor:pointer}\r\nbutton:hover{background:#233459}\r\n.read{font-size:11px;color:#88a; }\r\n</style></head>\r\n<body>\r\n<div class=\"console\" id=\"console\">\r\n  <div class=\"stage\"><canvas id=\"cv\"></canvas></div>\r\n  <div class=\"panel\">\r\n    <div><h1>Iluminação de 3 Pontos</h1>\r\n      <div class=\"sub\">Acenda e regule cada luz e veja como o artista aparece. Só contra-luz = silhueta; só frontal = chapado. O equilíbrio dá volume.</div></div>\r\n    <div id=\"lamps\"></div>\r\n    <div class=\"mission\" id=\"mission\"></div>\r\n    <div class=\"btns\"><button id=\"reset\">Apagar tudo</button><button id=\"next\">Próxima missão ▸</button></div>\r\n  </div>\r\n</div>\r\n<script>\r\nconst L=[\r\n {k:''front'',nm:''FRONTAL / Key'',desc:''À frente, ~45°. A plateia vê o rosto.'',on:false,v:75,col:''#fff2d8''},\r\n {k:''fill'', nm:''FILL'',        desc:''Lado oposto ao key. Suaviza a sombra.'',on:false,v:45,col:''#eef4ff''},\r\n {k:''back'', nm:''CONTRA-LUZ'',  desc:''Atrás/acima. Separa do fundo, dá brilho.'',on:false,v:80,col:''#dceaff''},\r\n {k:''cyc'',  nm:''FUNDO / Cyc'', desc:''Colore o ciclorama atrás.'',on:false,v:60,col:''#3a6bff''},\r\n];\r\nconst lampsEl=document.getElementById(''lamps'');\r\nL.forEach(l=>{const el=document.createElement(''div'');el.className=''lamp'';el.dataset.k=l.k;\r\n el.innerHTML=`<div class=\"sw\" data-sw></div><div class=\"nm\" style=\"color:${l.col}\">${l.nm}</div><div class=\"desc\">${l.desc}</div><input type=\"range\" min=\"0\" max=\"100\" value=\"${l.v}\" data-r>`;\r\n lampsEl.appendChild(el);\r\n el.querySelector(''[data-sw]'').onclick=()=>{l.on=!l.on;render();};\r\n el.querySelector(''[data-r]'').oninput=e=>{l.v=+e.target.value;render();};\r\n});\r\nconst cv=document.getElementById(''cv'');const ctx=cv.getContext(''2d'');\r\nfunction sizeCanvas(){const r=cv.getBoundingClientRect();const dpr=Math.min(2,devicePixelRatio||1);cv.width=r.width*dpr;cv.height=r.height*dpr;ctx.setTransform(dpr,0,0,dpr,0,0);draw();}\r\nfunction lampByK(k){return L.find(x=>x.k===k);}\r\nfunction amt(k){const l=lampByK(k);return l.on?l.v/100:0;}\r\nfunction draw(){\r\n const r=cv.getBoundingClientRect();const W=r.width,H=r.height;ctx.clearRect(0,0,W,H);\r\n // ciclorama (fundo)\r\n const cyc=amt(''cyc'');const cl=lampByK(''cyc'');\r\n ctx.fillStyle=''#05070c'';ctx.fillRect(0,0,W,H);\r\n if(cyc>0){const gr=ctx.createLinearGradient(0,0,0,H*0.82);gr.addColorStop(0,hex(cl.col,cyc*0.9));gr.addColorStop(1,hex(cl.col,cyc*0.25));ctx.fillStyle=gr;ctx.fillRect(0,0,W,H*0.82);}\r\n // chão\r\n ctx.fillStyle=''#0a0d15'';ctx.fillRect(0,H*0.82,W,H*0.18);\r\n const cx=W*0.5, groundY=H*0.82, headY=H*0.30;\r\n const front=amt(''front''),fill=amt(''fill''),back=amt(''back'');\r\n // sombra no chão (só com frontal/fill)\r\n const frontish=Math.max(front,fill*0.7);\r\n if(frontish>0){ctx.fillStyle=`rgba(0,0,0,${0.35*frontish})`;ctx.beginPath();ctx.ellipse(cx+18*frontish,groundY+4,60,12,0,0,7);ctx.fill();}\r\n // brilho de contra no chão\r\n if(back>0){const bg=ctx.createRadialGradient(cx,headY,4,cx,headY,H*0.5);bg.addColorStop(0,hex(lampByK(''back'').col,back*0.28));bg.addColorStop(1,''rgba(0,0,0,0)'');ctx.fillStyle=bg;ctx.fillRect(0,0,W,H);}\r\n // ── artista ──\r\n // luz total no corpo: soma frontal+fill principalmente; back contorna\r\n const bodyLight=Math.min(1,front*0.9+fill*0.6);\r\n const fc=lampByK(''front''),flc=lampByK(''fill'');\r\n // cor de corpo = mistura key/fill ponderada\r\n let br= front>0||fill>0 ? mix(fc.col,front,flc.col,fill) : {r:16,g:20,b:32};\r\n const baseL=0.12+0.88*bodyLight;\r\n const bodyCol=`rgb(${Math.round(br.r*baseL)},${Math.round(br.g*baseL)},${Math.round(br.b*baseL)})`;\r\n // corpo\r\n ctx.fillStyle=bodyCol;\r\n ctx.beginPath();ctx.moveTo(cx-26,groundY);ctx.lineTo(cx-16,headY+34);ctx.lineTo(cx+16,headY+34);ctx.lineTo(cx+26,groundY);ctx.closePath();ctx.fill();\r\n // cabeça\r\n ctx.beginPath();ctx.ellipse(cx,headY,17,20,0,0,7);ctx.fillStyle=bodyCol;ctx.fill();\r\n // rim light (contra) — contorno claro\r\n if(back>0){ctx.lineWidth=3;ctx.strokeStyle=hex(lampByK(''back'').col,Math.min(1,back));\r\n  ctx.beginPath();ctx.ellipse(cx,headY,17,20,0,-1.9,-0.2);ctx.stroke();\r\n  ctx.beginPath();ctx.moveTo(cx+26,groundY);ctx.lineTo(cx+16,headY+34);ctx.stroke();\r\n  ctx.beginPath();ctx.moveTo(cx-26,groundY);ctx.lineTo(cx-16,headY+34);ctx.stroke();}\r\n // rosto: só aparece com frontal/fill\r\n if(bodyLight>0.15){ctx.fillStyle=`rgba(0,0,0,${0.5})`;ctx.beginPath();ctx.arc(cx-6,headY-2,1.6,0,7);ctx.arc(cx+6,headY-2,1.6,0,7);ctx.fill();}\r\n // rótulo de diagnóstico\r\n let msg='''',mc=''#7f96bb'';\r\n if(back>0.1&&bodyLight<0.15){msg=''⚠ Só contra-luz: o artista virou SILHUETA — a plateia não vê o rosto.'';mc=''#ffcf6b'';}\r\n else if(bodyLight>0.15&&back<0.1){msg=''Rosto visível, mas sem contra-luz ele “gruda” no fundo (chapado).'';mc=''#cfe0ff'';}\r\n else if(bodyLight>0.15&&back>0.1&&fill>0.05){msg=''✓ Frontal + fill + contra = imagem tridimensional e legível.'';mc=''#39d98a'';}\r\n else if(bodyLight<0.05&&back<0.05&&cyc<0.05){msg=''Palco escuro — acenda alguma luz.'';}\r\n ctx.fillStyle=mc;ctx.font=''11.5px system-ui'';ctx.fillText(msg,12,H-14);\r\n}\r\nfunction hex(h,a){const c=h.replace(''#'','''');const r=parseInt(c.substr(0,2),16),g=parseInt(c.substr(2,2),16),b=parseInt(c.substr(4,2),16);return `rgba(${r},${g},${b},${a})`;}\r\nfunction mix(h1,w1,h2,w2){const p=x=>({r:parseInt(x.substr(1,2),16),g:parseInt(x.substr(3,2),16),b:parseInt(x.substr(5,2),16)});const a=p(h1),b=p(h2);const t=w1+w2||1;return {r:(a.r*w1+b.r*w2)/t,g:(a.g*w1+b.g*w2)/t,b:(a.b*w1+b.b*w2)/t};}\r\nfunction render(){L.forEach(l=>{const el=lampsEl.querySelector(`[data-k=\"${l.k}\"]`);el.querySelector(''[data-sw]'').classList.toggle(''on'',l.on);});draw();checkMission();}\r\n// missões\r\nconst M=[\r\n {t:''Acenda <b>só o contra-luz</b> e veja o problema da silhueta.'',ok:()=>amt(''back'')>0.3&&amt(''front'')<0.05&&amt(''fill'')<0.05},\r\n {t:''Agora acenda a <b>luz frontal (key)</b> para a plateia ver o rosto.'',ok:()=>amt(''front'')>0.4&&amt(''back'')>0.2},\r\n {t:''Monte os <b>3 pontos</b>: frontal + fill + contra-luz, todos acesos.'',ok:()=>amt(''front'')>0.4&&amt(''fill'')>0.2&&amt(''back'')>0.3},\r\n {t:''Acrescente cor no <b>fundo (cyc)</b> sem apagar o artista.'',ok:()=>amt(''cyc'')>0.3&&amt(''front'')>0.3&&amt(''back'')>0.2},\r\n];\r\nlet mi=0;\r\nfunction drawMission(){document.getElementById(''mission'').innerHTML=`<div><b>Missão ${mi+1}/${M.length}:</b> ${M[mi].t}</div><div class=\"mrow\"><span class=\"dot\" id=\"mdot\"></span><span id=\"mstat\">…</span></div>`;}\r\nfunction checkMission(){const dot=document.getElementById(''mdot'');if(!dot)return;if(M[mi].ok()){dot.classList.add(''ok'');document.getElementById(''mstat'').textContent=''✓ Feito! Próxima missão.'';}else{dot.classList.remove(''ok'');document.getElementById(''mstat'').textContent=''Ajuste as luzes…'';}}\r\ndocument.getElementById(''next'').onclick=()=>{mi=(mi+1)%M.length;drawMission();render();};\r\ndocument.getElementById(''reset'').onclick=()=>{L.forEach(l=>l.on=false);render();};\r\nfunction fit(){const DW=1000,DH=620;const vw=innerWidth,vh=innerHeight;const scrH=(window.screen&&screen.height)||vh;const iframeTaller=vh>scrH+8;const visH=Math.min(vh,scrH);const headerAllow=iframeTaller?84:(vh>700?24:6);const effVh=Math.max(240,visH-headerAllow);const z=Math.min(vw/DW,effVh/DH);document.getElementById(''console'').style.zoom=z;requestAnimationFrame(sizeCanvas);}\r\naddEventListener(''resize'',fit);drawMission();render();fit();setTimeout(fit,60);\r\n</script></body></html>\r\n"}]'::jsonb);

-- AULA 5 [M2.1]: DMX512: o idioma entre a mesa e as luzes
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('10c00000-b551-4c00-9000-0000000b0005','10c00000-b551-4c00-9000-0000000000a2','DMX512: o idioma entre a mesa e as luzes','texto','<p><strong>DMX512 é o idioma que a mesa usa para conversar com as luzes.</strong> Quando você sobe um fader e a moving abre, escurece ou muda de cor, foi o DMX que levou essa ordem da mesa até a fixture. Entender esse protocolo é o que separa quem "aperta botão" de quem realmente opera luz. Nesta aula você vai entender como o comando viaja e por que cada número importa.</p>

<figure style="margin:16px 0;text-align:center"><img src="https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/img-luz-basico/dmx-daisy-chain.jpg" alt="Duas fixtures ligadas por um cabo DMX em cadeia: o cabo sai do DMX OUT de uma e entra no DMX IN da outra." style="max-width:100%;border-radius:10px;border:1px solid rgba(0,0,0,.12)" /><figcaption style="font-size:12px;opacity:.75;margin-top:6px">O daisy chain: o cabo DMX sai do OUT de uma fixture e entra no IN da próxima — o sinal viaja em cadeia até o terminador.</figcaption></figure>

<h3>O que é DMX512</h3>
<p>DMX512 é o <strong>protocolo padrão</strong> da iluminação de palco: a linguagem única que praticamente toda mesa e toda fixture do mundo entendem. O número "512" não é enfeite — ele diz que um <strong>UNIVERSO</strong> DMX tem exatamente <strong>512 canais</strong>. Um universo é o "pacote" de 512 controles que a mesa consegue mandar por uma única linha.</p>

<h3>Canal e valor: os dois conceitos que você precisa dominar</h3>
<p>Um <strong>CANAL</strong> é um controle individual — uma "alavanca" para uma função. Cada fixture usa vários canais: um canal de <em>dimmer</em> (intensidade), um de <em>vermelho</em>, um de <em>verde</em>, um de <em>azul</em>, um de <em>pan</em> (giro horizontal), um de <em>tilt</em>, e assim por diante.</p>
<p>Cada canal carrega um <strong>VALOR de 0 a 255</strong> (são 8 bits, 256 níveis). A regra é simples: <strong>0 = nada/apagado</strong> e <strong>255 = máximo</strong>. Exemplos concretos:</p>
<ul>
<li>Canal <strong>Dimmer</strong> em 255 = luz a 100%. Em 128, mais ou menos meia luz. Em 0, apagada.</li>
<li>Canal <strong>Vermelho</strong> em 255 = vermelho no talo. Em 128 = meio vermelho.</li>
<li>Canal <strong>Pan</strong> em 0 = todo para um lado; em 255 = todo para o outro.</li>
</ul>
<p>Você nunca "manda cor" de forma abstrata: você manda <em>números</em> em canais, e a fixture obedece.</p>

<h3>Como o sinal viaja: daisy chain</h3>
<p>O sinal sai da mesa por um <strong>cabo DMX</strong> e entra na primeira fixture pelo conector <strong>DMX IN</strong>. Dessa mesma fixture ele sai pelo <strong>DMX OUT (ou THRU)</strong> e segue para a fixture 2, que repassa para a 3, e assim por diante. Essa ligação em cadeia, uma luz alimentando a próxima, é o <strong>DAISY CHAIN</strong>.</p>
<p>No <strong>fim da linha</strong> vai um <strong>TERMINADOR</strong>: um conector com resistor de <strong>120 ohms</strong> plugado no DMX OUT da última fixture. Sem ele, o sinal "bate no fim e volta" (reflexão), causando erros intermitentes — luz piscando, moving tremendo, cor errada. Terminador barato resolve dor de cabeça cara.</p>

<h3>Tudo ao mesmo tempo, o tempo todo</h3>
<p>A mesa não manda um canal por vez. Ela envia os <strong>512 valores juntos</strong>, empacotados num <strong>frame (pacote) DMX</strong>, e repete esse envio cerca de <strong>44 vezes por segundo</strong>. Por isso todas as luzes atualizam juntas, em tempo real: quando você move um fader, o próximo frame já leva o novo valor para todas as fixtures. É esse refresh constante que dá a sensação de resposta instantânea.</p>

<h3>Limites que você vai esbarrar na prática</h3>
<ul>
<li><strong>~32 fixtures por linha DMX:</strong> passou disso, o sinal enfraquece — use um splitter DMX para abrir novos ramos.</li>
<li><strong>512 canais por universo:</strong> some os canais de todas as fixtures da linha; ao estourar 512, você precisa de outro universo.</li>
<li><strong>Shows grandes usam VÁRIOS universos:</strong> Universo 1, Universo 2, Universo 3... cada um com seus 512 canais. Protocolos por rede como <strong>Art-Net</strong> e <strong>sACN</strong> mandam muitos universos por um único cabo de rede — assunto que você aprofunda no Pleno.</li>
</ul>

<h3>Duas características que explicam muito erro</h3>
<p>O DMX é <strong>UNIDIRECIONAL</strong>: só a mesa fala, a fixture só ouve. Ela não devolve status nem avisa se recebeu — por isso o teste é sempre visual, olhando a luz. E o DMX <strong>não se endereça sozinho</strong>: se você não disser um endereço a cada fixture, várias respondem aos mesmos canais e se movem iguais. Dar endereço a cada luminária é o tema da próxima aula.</p>

<h3>Resumo prático</h3>
<p><strong>Universo = 512 canais; canal = um controle; valor = 0 a 255.</strong> A mesa manda os 512 valores ~44 vezes por segundo por um cabo em daisy chain, com terminador de 120 ohms no fim. É unidirecional e não se endereça sozinho: cada fixture precisa do seu endereço — próxima aula.</p>',18,1,true,false);
