insert into public.ai_animations (lesson_id,tipo,status,model,custo_usd,roteiro,urls) values ('10c00000-b551-4c00-9000-0000000b0005','interactive','ready','handcrafted-interactive',0,'{"titulo":"Simulador — Sinal DMX e Daisy Chain","metadata":{"titulo_aula":"Simulador — Sinal DMX e Daisy Chain","total_cenas":1,"duracao_total":0,"abordagem_didatica":"Simulador interativo — pratique movendo os controles"},"cenas":[{"numero":1,"titulo":"Simulador — Sinal DMX e Daisy Chain","modo":"widget","narracao":"Ligue as fixtures em cadeia (daisy chain), use cabo DMX e terminador, e veja o sinal chegar. Complete as 3 missões.","explicacao_texto":"Ligue as fixtures em cadeia (daisy chain), use cabo DMX e terminador, e veja o sinal chegar. Complete as 3 missões.","destaques":["OUT → IN em cadeia","Cabo DMX (não de microfone)","Terminador 120Ω na última","512 valores por universo"]}]}'::jsonb,'[{"html":"<!doctype html><html lang=\"pt-BR\"><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no\">\r\n<title>Simulador — Sinal DMX e Daisy Chain</title>\r\n<style>\r\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\r\nhtml,body{height:100%;background:#0b0e14;color:#e7ecf3;font-family:system-ui,Segoe UI,Roboto,Arial,sans-serif;overflow:hidden}\r\nbody{display:flex;align-items:center;justify-content:center}\r\n.console{width:1010px;height:610px;background:linear-gradient(180deg,#121722,#0d111a);border:1px solid #223049;border-radius:14px;padding:18px;display:flex;flex-direction:column;gap:12px;box-shadow:0 10px 40px #0008}\r\nh1{font-size:15px;font-weight:700;color:#cfe0ff}\r\n.sub{font-size:11.5px;color:#8aa0c2;line-height:1.4}\r\n.stage{flex:1;background:#04060a;border:1px solid #1c2740;border-radius:12px;position:relative;overflow:hidden}\r\n.stage canvas{width:100%;height:100%;display:block}\r\n.controls{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}\r\n.card{background:#0e1421;border:1px solid #22314c;border-radius:10px;padding:9px 11px}\r\n.card h3{font-size:11px;color:#9db6df;margin-bottom:6px;font-weight:700}\r\n.opt{display:flex;gap:6px;flex-wrap:wrap}\r\n.opt button{flex:1;min-width:0}\r\nbutton{background:#1b2740;color:#dce7fb;border:1px solid #33507f;border-radius:8px;padding:6px 8px;font-size:11px;font-weight:600;cursor:pointer;white-space:nowrap}\r\nbutton:hover{background:#233459}button.sel{background:#2b5aa8;border-color:#4d86e0}\r\n.bot{display:grid;grid-template-columns:2fr 1fr;gap:12px;align-items:stretch}\r\n.mission{background:#0e1626;border:1px solid #24406e;border-radius:10px;padding:9px 11px;font-size:11.5px;line-height:1.45}\r\n.mrow{display:flex;align-items:center;gap:8px;margin-top:4px}.dot{width:13px;height:13px;border-radius:50%;border:2px solid #37507a;flex:none}.dot.ok{background:#39d98a;border-color:#39d98a}\r\n.status{border-radius:10px;padding:9px 11px;font-size:12px;font-weight:600;display:flex;flex-direction:column;justify-content:center;gap:3px}\r\n.status small{font-weight:400;font-size:10.5px;opacity:.85}\r\n</style></head>\r\n<body>\r\n<div class=\"console\" id=\"console\">\r\n  <div><h1>Como o sinal DMX viaja — Daisy Chain</h1>\r\n    <div class=\"sub\">A mesa manda os 512 valores em cadeia: <b>OUT</b> de uma fixture vai no <b>IN</b> da próxima. Use <b>cabo DMX</b> (não de microfone) e <b>terminador</b> na última. Veja o sinal chegar (ou falhar).</div></div>\r\n  <div class=\"stage\"><canvas id=\"cv\"></canvas></div>\r\n  <div class=\"controls\">\r\n    <div class=\"card\"><h3>Nº de fixtures na linha</h3><div class=\"opt\" id=\"nfx\"></div></div>\r\n    <div class=\"card\"><h3>Tipo de cabo</h3><div class=\"opt\" id=\"cable\">\r\n      <button data-cable=\"dmx\">Cabo DMX 120Ω</button><button data-cable=\"mic\">Cabo de microfone</button></div></div>\r\n    <div class=\"card\"><h3>Terminador na última</h3><div class=\"opt\" id=\"term\">\r\n      <button data-term=\"1\">Com terminador</button><button data-term=\"0\">Sem terminador</button></div></div>\r\n    <div class=\"card\"><h3>Simulação</h3><div class=\"opt\"><button id=\"play\">▶ Enviar frame DMX</button></div></div>\r\n  </div>\r\n  <div class=\"bot\">\r\n    <div class=\"mission\" id=\"mission\"></div>\r\n    <div class=\"status\" id=\"status\"></div>\r\n  </div>\r\n</div>\r\n<script>\r\nconst st={n:4,cable:''mic'',term:0,anim:0};\r\nconst nfxEl=document.getElementById(''nfx'');[2,4,8,16].forEach(n=>{const b=document.createElement(''button'');b.textContent=n;b.dataset.n=n;b.onclick=()=>{st.n=n;syncBtns();draw();check();};nfxEl.appendChild(b);});\r\ndocument.querySelectorAll(''[data-cable]'').forEach(b=>b.onclick=()=>{st.cable=b.dataset.cable;syncBtns();draw();check();});\r\ndocument.querySelectorAll(''[data-term]'').forEach(b=>b.onclick=()=>{st.term=+b.dataset.term;syncBtns();draw();check();});\r\nfunction syncBtns(){nfxEl.querySelectorAll(''button'').forEach(b=>b.classList.toggle(''sel'',+b.dataset.n===st.n));\r\n document.querySelectorAll(''[data-cable]'').forEach(b=>b.classList.toggle(''sel'',b.dataset.cable===st.cable));\r\n document.querySelectorAll(''[data-term]'').forEach(b=>b.classList.toggle(''sel'',+b.dataset.term===st.term));}\r\n// qualidade do sinal\r\nfunction quality(){\r\n // cabo de microfone: erro cresce com nº de fixtures. sem terminador: erro em linhas longas.\r\n let ok=true, reason=[];\r\n if(st.cable===''mic''){ok=false;reason.push(''cabo de microfone (75Ω) em DMX causa erros intermitentes'');}\r\n if(!st.term && st.n>=4){ok=false;reason.push(''linha longa sem terminador reflete o sinal'');}\r\n if(!st.term && st.n<4){reason.push(''curta funciona sem terminador, mas o certo é terminar'');}\r\n return {ok,reason};\r\n}\r\nconst cv=document.getElementById(''cv'');const ctx=cv.getContext(''2d'');\r\nfunction sizeCanvas(){const r=cv.getBoundingClientRect();const dpr=Math.min(2,devicePixelRatio||1);cv.width=r.width*dpr;cv.height=r.height*dpr;ctx.setTransform(dpr,0,0,dpr,0,0);draw();}\r\nfunction draw(){const r=cv.getBoundingClientRect();const W=r.width,H=r.height;ctx.clearRect(0,0,W,H);ctx.fillStyle=''#04060a'';ctx.fillRect(0,0,W,H);\r\n const q=quality();const y=H*0.4;\r\n const showN=Math.min(st.n,8);const total=showN+1;const gap=W/(total+1);\r\n // mesa\r\n const mx=gap*0.9;ctx.fillStyle=''#1a2740'';ctx.strokeStyle=''#3f7bd6'';ctx.lineWidth=2;ctx.beginPath();ctx.roundRect(mx-26,y-22,52,44,7);ctx.fill();ctx.stroke();\r\n ctx.fillStyle=''#cfe0ff'';ctx.font=''10px system-ui'';ctx.textAlign=''center'';ctx.fillText(''MESA'',mx,y+2);ctx.fillText(''DMX OUT'',mx,y+16);\r\n // fixtures\r\n const xs=[mx];\r\n for(let i=0;i<showN;i++){const x=gap*(i+2);xs.push(x);const good=q.ok;\r\n  // cabo do anterior\r\n  const px=xs[i];const cableCol=st.cable===''mic''?''#c9622e'':''#3f7bd6'';\r\n  ctx.strokeStyle=cableCol;ctx.lineWidth=3;ctx.beginPath();ctx.moveTo(px+26,y);ctx.lineTo(x-18,y);ctx.stroke();\r\n  // fixture box\r\n  ctx.fillStyle=''#141b28'';ctx.strokeStyle=''#26324a'';ctx.lineWidth=1.5;ctx.beginPath();ctx.roundRect(x-18,y-16,36,32,6);ctx.fill();ctx.stroke();\r\n  // luz acesa se sinal ok (com leve piscar se ruim)\r\n  let on = good ? 1 : (Math.random()<0.45?1:0.15);\r\n  const col=`rgba(120,190,255,${on})`;ctx.fillStyle=col;ctx.beginPath();ctx.arc(x,y,6,0,7);ctx.fill();\r\n  if(!good && on<0.5){ctx.fillStyle=''#ff6b6b'';ctx.font=''9px system-ui'';ctx.fillText(''erro'',x,y+27);}else{ctx.fillStyle=''#7f96bb'';ctx.font=''9px system-ui'';ctx.fillText(''IN→OUT'',x,y+27);}\r\n }\r\n // terminador ou ponta aberta\r\n const lastx=xs[xs.length-1];\r\n if(st.term){ctx.strokeStyle=''#39d98a'';ctx.lineWidth=3;ctx.beginPath();ctx.moveTo(lastx+18,y);ctx.lineTo(lastx+40,y);ctx.stroke();ctx.fillStyle=''#39d98a'';ctx.beginPath();ctx.arc(lastx+44,y,5,0,7);ctx.fill();ctx.fillStyle=''#39d98a'';ctx.font=''9px system-ui'';ctx.fillText(''120Ω'',lastx+44,y+20);}\r\n else{ctx.strokeStyle=''#ff7b7b'';ctx.setLineDash([4,3]);ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(lastx+18,y);ctx.lineTo(lastx+42,y);ctx.stroke();ctx.setLineDash([]);ctx.fillStyle=''#ff7b7b'';ctx.font=''9px system-ui'';ctx.fillText(''ponta aberta'',lastx+30,y+20);}\r\n if(st.n>showN){ctx.fillStyle=''#7f96bb'';ctx.font=''10px system-ui'';ctx.fillText(''… +''+(st.n-showN)+'' fixtures'',W-70,y);}\r\n ctx.textAlign=''left'';\r\n // pacote animado\r\n if(st.anim>0){const p=(1-st.anim);const px=mx+ (lastx-mx)*p;ctx.fillStyle=''#ffe08a'';ctx.beginPath();ctx.arc(px,y-30,5,0,7);ctx.fill();ctx.fillStyle=''#ffe08a'';ctx.font=''9px system-ui'';ctx.fillText(''frame'',px-12,y-38);}\r\n}\r\nfunction animate(){if(st.anim>0){st.anim-=0.02;if(st.anim<0)st.anim=0;draw();requestAnimationFrame(animate);}}\r\ndocument.getElementById(''play'').onclick=()=>{st.anim=1;animate();};\r\nfunction setStatus(){const q=quality();const el=document.getElementById(''status'');\r\n if(q.ok){el.style.background=''#12331f'';el.style.borderLeft=''4px solid #39d98a'';el.innerHTML=''✓ Sinal íntegro<small>Todas as fixtures respondem estáveis.</small>'';}\r\n else{el.style.background=''#331515'';el.style.borderLeft=''4px solid #ff6b6b'';el.innerHTML=''⚠ Sinal com falha<small>''+q.reason.join(''; '')+''.</small>'';}\r\n}\r\nconst M=[\r\n {t:''A linha está com <b>cabo de microfone</b> e piscando. Troque para <b>cabo DMX</b>.'',ok:()=>st.cable===''dmx''},\r\n {t:''Com 8 fixtures e <b>sem terminador</b> o sinal reflete. Ligue o <b>terminador 120Ω</b>.'',ok:()=>st.n>=8&&st.term===1&&st.cable===''dmx''},\r\n {t:''Monte uma linha <b>100% correta</b>: cabo DMX + terminador, com qualquer nº de fixtures.'',ok:()=>quality().ok},\r\n];\r\nlet mi=0;\r\nfunction drawMission(){document.getElementById(''mission'').innerHTML=`<div><b>Missão ${mi+1}/${M.length}:</b> ${M[mi].t}</div><div class=\"mrow\"><span class=\"dot\" id=\"mdot\"></span><span id=\"mstat\">…</span></div>`;}\r\nfunction check(){setStatus();const dot=document.getElementById(''mdot'');if(!dot)return;if(M[mi].ok()){dot.classList.add(''ok'');document.getElementById(''mstat'').textContent=''✓ Feito! Próxima missão.'';}else{dot.classList.remove(''ok'');document.getElementById(''mstat'').textContent=''Ajuste a ligação…'';}}\r\ndocument.getElementById(''next'').onclick=()=>{};\r\ndocument.getElementById(''mission'').addEventListener(''click'',()=>{});\r\n// botão próxima dentro da mission card via status? add a next button\r\nconst nb=document.createElement(''button'');nb.textContent=''Próxima missão ▸'';nb.style.marginTop=''6px'';nb.onclick=()=>{mi=(mi+1)%M.length;drawMission();check();};\r\ndocument.getElementById(''mission'').after(nb);nb.parentNode&&0;\r\nfunction fit(){const DW=1010,DH=610;const vw=innerWidth,vh=innerHeight;const scrH=(window.screen&&screen.height)||vh;const iframeTaller=vh>scrH+8;const visH=Math.min(vh,scrH);const headerAllow=iframeTaller?84:(vh>700?24:6);const effVh=Math.max(240,visH-headerAllow);const z=Math.min(vw/DW,effVh/DH);document.getElementById(''console'').style.zoom=z;requestAnimationFrame(sizeCanvas);}\r\naddEventListener(''resize'',fit);syncBtns();drawMission();check();fit();setTimeout(fit,60);\r\n</script></body></html>\r\n"}]'::jsonb);

-- AULA 6 [M2.2]: Endereçamento e patch: o CEP de cada luminária
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('10c00000-b551-4c00-9000-0000000b0006','10c00000-b551-4c00-9000-0000000000a2','Endereçamento e patch: o CEP de cada luminária','texto','<p><strong>Endereçar é dar um CEP para cada luminária.</strong> A mesa manda os 512 valores do universo para todo mundo ao mesmo tempo; o endereço é o que faz cada fixture "escutar" só os canais que são dela. Errou o endereço, a luz obedece a ordem errada — ou pior, obedece junto com outra. Nesta aula você aprende a distribuir endereços sem sobrepor.</p>

<h3>Endereço inicial: onde a luz "mora"</h3>
<p>Cada fixture precisa de um <strong>ENDEREÇO INICIAL</strong> (<em>start address</em>): o número do <strong>primeiro canal</strong> dela dentro do universo. É o CEP da luminária — diz à mesa em que "rua e número" aquela luz recebe seus comandos. Se o endereço inicial é 1, a fixture começa a ler a partir do canal 1. Se é 50, começa no 50.</p>

<h3>Footprint: quantos canais ela ocupa</h3>
<p>A partir do endereço inicial, a fixture ocupa uma faixa de canais. Esse tamanho é o <strong>FOOTPRINT</strong> (pegada), e ele depende do <strong>MODO</strong> que você escolhe no menu da própria fixture:</p>
<ul>
<li><strong>PAR LED em modo "3 canais"</strong> (R, G, B): footprint de 3 canais.</li>
<li><strong>Mesmo PAR em modo "8 canais"</strong> (Dimmer, R, G, B, Strobo, Macro de cor, velocidade, programa): footprint de 8 canais.</li>
<li><strong>Moving head:</strong> costuma ocupar 16, 24 ou mais canais, porque tem pan, tilt, cor, gobo, foco, íris, prisma...</li>
</ul>
<p>Mesma fixture, footprints diferentes conforme o modo. Por isso o modo tem que estar decidido <em>antes</em> de você planejar os endereços.</p>

<figure style="margin:16px 0;text-align:center"><img src="https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/img-luz-basico/fixture-menu-dmx.jpg" alt="Painel traseiro de um moving head com o pequeno display digital mostrando o menu de endereço DMX e botões de navegação." style="max-width:100%;border-radius:10px;border:1px solid rgba(0,0,0,.12)" /><figcaption style="font-size:12px;opacity:.75;margin-top:6px">No display da fixture você ajusta o endereço DMX inicial e o modo (footprint). O que está aqui tem que bater com o patch da mesa.</figcaption></figure>

<h3>A regra de ouro: não sobrepor</h3>
<p>A próxima fixture começa <strong>depois</strong> de onde a anterior termina. Veja o passo a passo com PARs idênticos de <strong>8 canais</strong>:</p>
<ul>
<li><strong>Fixture 1</strong> no endereço <strong>1</strong> → ocupa canais <strong>1 a 8</strong>.</li>
<li><strong>Fixture 2</strong> começa no <strong>9</strong> → ocupa <strong>9 a 16</strong>.</li>
<li><strong>Fixture 3</strong> começa no <strong>17</strong> → ocupa <strong>17 a 24</strong>. E segue: 25, 33, 41...</li>
</ul>
<p>A conta é sempre <em>endereço anterior + footprint</em>. Erro clássico: pôr a Fixture 2 no endereço <strong>5</strong>. Aí ela ocupa 5 a 12, que <strong>invade</strong> os canais 5 a 8 da Fixture 1 — as duas passam a reagir juntas nos canais sobrepostos e você perde o controle individual. Sobreposição não é opinião: é conflito garantido.</p>

<h3>Patch na mesa: dizer o que está onde</h3>
<p><strong>PATCH</strong> é o cadastro que você faz na mesa: informar <em>qual modelo</em> de fixture está em <em>qual endereço</em>. Com o patch certo, a mesa mostra os controles corretos daquela luz — foco, gobo, cor, prisma — em vez de canais numerados soltos. A regra é inegociável: <strong>o endereço ajustado na fixture e o endereço declarado no patch têm que BATER</strong>. Se a fixture está no 9 mas você fez o patch no 1, a mesa comanda o vazio e a luz fica muda.</p>

<h3>Quando o endereço igual é de propósito</h3>
<p>Duas fixtures no <strong>mesmo endereço</strong> fazem exatamente a mesma coisa — viram <strong>clones</strong>. Isso é útil de propósito: um par simétrico de luzes que deve subir, colorir e mover igual, controlado por um comando só. O preço é claro: você perde o controle individual de cada uma. Use quando quiser espelhamento; evite quando precisar de cada luz fazendo algo diferente.</p>

<h3>Onde se ajusta o endereço</h3>
<ul>
<li><strong>Display/menu da fixture:</strong> nos modelos atuais, botões up/down navegam até o número do endereço e o modo. É o jeito mais comum e rápido.</li>
<li><strong>Dip-switches:</strong> em fixtures antigas, um bloco de chavinhas define o endereço em <strong>binário</strong> — cada chave vale um número (1, 2, 4, 8, 16...) e você soma as que estão ligadas para chegar ao endereço desejado. Mais trabalhoso, mas o princípio é o mesmo: definir o primeiro canal da fixture.</li>
</ul>

<h3>Resumo prático</h3>
<p><strong>Endereço inicial = primeiro canal da fixture; footprint = quantos canais ela ocupa no modo escolhido.</strong> A próxima começa em <em>endereço + footprint</em> para nunca sobrepor. Faça o patch na mesa com o mesmo endereço e o mesmo modelo — endereço e patch têm que bater. Endereço igual só quando quiser clones.</p>',20,2,true,false);
