insert into public.ai_animations (lesson_id,tipo,status,model,custo_usd,roteiro,urls) values ('10c00000-b551-4c00-9000-0000000b0006','interactive','ready','handcrafted-interactive',0,'{"titulo":"Simulador — Endereçamento e Patch DMX","metadata":{"titulo_aula":"Simulador — Endereçamento e Patch DMX","total_cenas":1,"duracao_total":0,"abordagem_didatica":"Simulador interativo — pratique movendo os controles"},"cenas":[{"numero":1,"titulo":"Simulador — Endereçamento e Patch DMX","modo":"widget","narracao":"Dê a cada fixture um endereço inicial sem sobrepor, respeitando o footprint de cada modo. Complete as 4 missões.","explicacao_texto":"Dê a cada fixture um endereço inicial sem sobrepor, respeitando o footprint de cada modo. Complete as 4 missões.","destaques":["Endereço inicial (start address)","Footprint = canais por modo","Não sobrepor","Channel check"]}]}'::jsonb,'[{"html":"<!doctype html><html lang=\"pt-BR\"><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no\">\r\n<title>Simulador — Endereçamento e Patch DMX</title>\r\n<style>\r\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\r\nhtml,body{height:100%;background:#0b0e14;color:#e7ecf3;font-family:system-ui,Segoe UI,Roboto,Arial,sans-serif;overflow:hidden}\r\nbody{display:flex;align-items:center;justify-content:center}\r\n.console{width:1010px;height:625px;background:linear-gradient(180deg,#121722,#0d111a);border:1px solid #223049;border-radius:14px;padding:16px 18px;display:flex;flex-direction:column;gap:12px;box-shadow:0 10px 40px #0008}\r\nh1{font-size:15px;font-weight:700;color:#cfe0ff}\r\n.sub{font-size:11.5px;color:#8aa0c2;line-height:1.4}\r\n.main{display:grid;grid-template-columns:1.25fr .75fr;gap:16px;flex:1;min-height:0}\r\n.left{display:flex;flex-direction:column;gap:8px;min-height:0}\r\n.fixtures{display:flex;flex-direction:column;gap:7px;overflow:auto;padding-right:4px}\r\n.fx{display:grid;grid-template-columns:26px 1fr auto auto;gap:9px;align-items:center;background:#0e1421;border:1px solid #22314c;border-radius:9px;padding:7px 9px}\r\n.fx.sel{border-color:#3f7bd6;box-shadow:0 0 0 1px #3f7bd6}\r\n.fx .ic{width:26px;height:26px;border-radius:6px;display:flex;align-items:center;justify-content:center;font-size:14px}\r\n.fx .nm{font-size:12px;font-weight:700}.fx .md{font-size:10.5px;color:#8298bd}\r\n.mode select{background:#0c1220;color:#dce7fb;border:1px solid #2b3c58;border-radius:6px;font-size:11px;padding:3px 4px}\r\n.addr{display:flex;align-items:center;gap:4px}\r\n.addr button{width:24px;height:24px;padding:0;font-size:15px;line-height:1}\r\n.addr input{width:52px;text-align:center;background:#0c1220;color:#fff;border:1px solid #2b3c58;border-radius:6px;font-size:12px;padding:4px;font-variant-numeric:tabular-nums}\r\n.chspan{font-size:10px;color:#7f96bb;min-width:66px;text-align:right}\r\n.chspan.bad{color:#ff7b7b;font-weight:700}\r\n.universe{background:#0a0f1a;border:1px solid #22314c;border-radius:9px;padding:8px}\r\n.ubar{display:grid;grid-template-columns:repeat(32,1fr);gap:1px;margin-top:5px}\r\n.cell{height:11px;background:#141c2c;border-radius:1px}\r\n.uleg{font-size:10px;color:#7f96bb;display:flex;justify-content:space-between}\r\n.right{display:flex;flex-direction:column;gap:10px;min-width:0}\r\n.stage{flex:1;background:#04060a;border:1px solid #1c2740;border-radius:10px;position:relative;overflow:hidden;min-height:120px}\r\n.stage canvas{width:100%;height:100%;display:block}\r\n.mission{background:#0e1626;border:1px solid #24406e;border-radius:10px;padding:9px 11px;font-size:11.5px;line-height:1.45}\r\n.mrow{display:flex;align-items:center;gap:8px;margin-top:4px}.dot{width:13px;height:13px;border-radius:50%;border:2px solid #37507a;flex:none}.dot.ok{background:#39d98a;border-color:#39d98a}\r\n.btns{display:flex;gap:7px;flex-wrap:wrap}\r\nbutton{background:#1b2740;color:#dce7fb;border:1px solid #33507f;border-radius:8px;padding:6px 10px;font-size:11.5px;font-weight:600;cursor:pointer}\r\nbutton:hover{background:#233459}\r\nbutton.p{background:#1e5a3a;border-color:#2f8f5b}button.p:hover{background:#256e47}\r\n</style></head>\r\n<body>\r\n<div class=\"console\" id=\"console\">\r\n  <div><h1>Endereçamento e Patch DMX <span style=\"font-weight:400;color:#7f96bb;font-size:12px\">— Universo 1</span></h1>\r\n    <div class=\"sub\">Dê a cada fixture um <b>endereço inicial</b> sem sobrepor. Cada modo ocupa um número de canais (<b>footprint</b>). A próxima fixture começa <b>depois</b> da anterior.</div></div>\r\n  <div class=\"main\">\r\n    <div class=\"left\">\r\n      <div class=\"fixtures\" id=\"fixtures\"></div>\r\n      <div class=\"universe\">\r\n        <div class=\"uleg\"><span>Mapa do Universo (canais 1–512 · mostrando 1–256)</span><span id=\"usumm\"></span></div>\r\n        <div class=\"ubar\" id=\"ubar\"></div>\r\n        <div class=\"uleg\" style=\"margin-top:4px\"><span>1</span><span>64</span><span>128</span><span>192</span><span>256</span></div>\r\n      </div>\r\n    </div>\r\n    <div class=\"right\">\r\n      <div class=\"stage\"><canvas id=\"cv\"></canvas></div>\r\n      <div class=\"btns\">\r\n        <button id=\"check\" class=\"p\">▶ Channel check (testar selecionada)</button>\r\n        <button id=\"auto\">Auto-endereçar em sequência</button>\r\n      </div>\r\n      <div class=\"mission\" id=\"mission\"></div>\r\n      <div class=\"btns\"><button id=\"next\">Próxima missão ▸</button></div>\r\n    </div>\r\n  </div>\r\n</div>\r\n<script>\r\nconst MODES={ ''PAR LED'':[{n:''3ch (RGB)'',f:3},{n:''4ch (RGBW)'',f:4},{n:''8ch (Dim+RGB+...)'',f:8}],\r\n ''Moving Wash'':[{n:''12ch básico'',f:12},{n:''16ch estendido'',f:16}],\r\n ''Moving Spot'':[{n:''16ch'',f:16},{n:''24ch'',f:24}] };\r\nconst FX=[\r\n {nm:''PAR LED 1'',type:''PAR LED'',ic:''🔴'',col:''#ff5a5a'',mode:0,addr:1},\r\n {nm:''PAR LED 2'',type:''PAR LED'',ic:''🟢'',col:''#48e06a'',mode:0,addr:1},\r\n {nm:''Moving Wash'',type:''Moving Wash'',ic:''🔵'',col:''#4d8bff'',mode:0,addr:1},\r\n {nm:''Moving Spot'',type:''Moving Spot'',ic:''⚪'',col:''#ffe08a'',mode:0,addr:1},\r\n];\r\nlet sel=0, testing=-1, testT=0;\r\nconst foot=fx=>MODES[fx.type][fx.mode].f;\r\nconst fixturesEl=document.getElementById(''fixtures'');\r\nfunction buildFixtures(){fixturesEl.innerHTML='''';FX.forEach((fx,i)=>{\r\n const el=document.createElement(''div'');el.className=''fx''+(i===sel?'' sel'':'''');\r\n const opts=MODES[fx.type].map((m,mi)=>`<option value=\"${mi}\" ${mi===fx.mode?''selected'':''''}>${m.n}</option>`).join('''');\r\n el.innerHTML=`<div class=\"ic\" style=\"background:${fx.col}22;color:${fx.col}\">${fx.ic}</div>\r\n  <div><div class=\"nm\">${fx.nm}</div><div class=\"md\">${fx.type} · ${foot(fx)} canais</div></div>\r\n  <div class=\"mode\"><select data-mode>${opts}</select></div>\r\n  <div class=\"addr\"><button data-dn>−</button><input data-addr value=\"${fx.addr}\"><button data-up>+</button></div>`;\r\n fixturesEl.appendChild(el);\r\n el.onclick=()=>{sel=i;buildFixtures();draw();};\r\n el.querySelector(''[data-mode]'').onchange=e=>{fx.mode=+e.target.value;update();};\r\n el.querySelector(''[data-addr]'').onchange=e=>{fx.addr=clamp(parseInt(e.target.value)||1);update();};\r\n el.querySelector(''[data-up]'').onclick=ev=>{ev.stopPropagation();fx.addr=clamp(fx.addr+1);update();};\r\n el.querySelector(''[data-dn]'').onclick=ev=>{ev.stopPropagation();fx.addr=clamp(fx.addr-1);update();};\r\n});\r\n // spans de canal e conflito\r\n FX.forEach((fx,i)=>{const el=fixturesEl.children[i];const end=fx.addr+foot(fx)-1;\r\n  const bad=conflicts(i);const span=document.createElement(''div'');span.className=''chspan''+(bad?'' bad'':'''');\r\n  span.textContent=(bad?''⚠ '':'''')+''ch ''+fx.addr+''–''+end;el.appendChild(span);});\r\n}\r\nfunction clamp(v){return Math.max(1,Math.min(512,v));}\r\nfunction conflicts(i){const a1=FX[i].addr,a2=a1+foot(FX[i])-1;return FX.some((o,j)=>{if(j===i)return false;const b1=o.addr,b2=o.addr+foot(o)-1;return a1<=b2&&b1<=a2;});}\r\nfunction anyConflict(){return FX.some((_,i)=>conflicts(i));}\r\n// universo bar\r\nconst ubar=document.getElementById(''ubar'');const CELLS=256;\r\nfor(let i=0;i<CELLS;i++){const c=document.createElement(''div'');c.className=''cell'';ubar.appendChild(c);}\r\nfunction paintUniverse(){const cells=ubar.children;for(let i=0;i<CELLS;i++)cells[i].style.background=''#141c2c'';\r\n // marca ocupação; conflito = vermelho\r\n const owner=new Array(CELLS).fill(-1);\r\n FX.forEach((fx,i)=>{for(let c=fx.addr;c<fx.addr+foot(fx);c++){const idx=c-1;if(idx<0||idx>=CELLS)continue;\r\n   if(owner[idx]===-1){owner[idx]=i;cells[idx].style.background=fx.col;}else{cells[idx].style.background=''#ff4d4d'';}}});\r\n document.getElementById(''usumm'').textContent=anyConflict()?''⚠ há sobreposição'':''sem conflitos ✓'';\r\n document.getElementById(''usumm'').style.color=anyConflict()?''#ff7b7b'':''#39d98a'';\r\n}\r\n// stage canvas — desenha 4 fixtures e pisca a testada\r\nconst cv=document.getElementById(''cv'');const ctx=cv.getContext(''2d'');\r\nfunction sizeCanvas(){const r=cv.getBoundingClientRect();const dpr=Math.min(2,devicePixelRatio||1);cv.width=r.width*dpr;cv.height=r.height*dpr;ctx.setTransform(dpr,0,0,dpr,0,0);draw();}\r\nfunction draw(){const r=cv.getBoundingClientRect();const W=r.width,H=r.height;ctx.clearRect(0,0,W,H);ctx.fillStyle=''#04060a'';ctx.fillRect(0,0,W,H);\r\n ctx.fillStyle=''#7f96bb'';ctx.font=''10.5px system-ui'';ctx.fillText(''Palco — channel check'',10,15);\r\n const n=FX.length;const gap=W/(n+1);\r\n FX.forEach((fx,i)=>{const x=gap*(i+1),y=H*0.3;const lit=(i===testing);const active=(i===sel);\r\n  ctx.fillStyle=active?''#22304a'':''#141b28'';ctx.strokeStyle=active?''#3f7bd6'':''#26324a'';ctx.lineWidth=1.5;\r\n  ctx.beginPath();ctx.roundRect(x-16,y-12,32,24,5);ctx.fill();ctx.stroke();\r\n  if(lit){const bg=ctx.createLinearGradient(0,y,0,H*0.95);bg.addColorStop(0,hex(fx.col,0.8));bg.addColorStop(1,hex(fx.col,0));\r\n   ctx.beginPath();ctx.moveTo(x-8,y+10);ctx.lineTo(x-34,H*0.92);ctx.lineTo(x+34,H*0.92);ctx.lineTo(x+8,y+10);ctx.closePath();ctx.fillStyle=bg;ctx.fill();\r\n   ctx.fillStyle=hex(fx.col,1);ctx.beginPath();ctx.arc(x,y,6,0,7);ctx.fill();}\r\n  ctx.fillStyle=lit?''#fff'':''#6b7f9e'';ctx.font=''9px system-ui'';ctx.textAlign=''center'';ctx.fillText(''@''+fx.addr,x,y+34);ctx.textAlign=''left'';});\r\n if(testing>=0){ctx.fillStyle=''#39d98a'';ctx.font=''11px system-ui'';ctx.fillText(''▶ Testando ''+FX[testing].nm+'' (endereço ''+FX[testing].addr+'')'',10,H-12);}\r\n}\r\nfunction hex(h,a){const c=h.replace(''#'','''');return `rgba(${parseInt(c.substr(0,2),16)},${parseInt(c.substr(2,2),16)},${parseInt(c.substr(4,2),16)},${a})`;}\r\nfunction update(){buildFixtures();paintUniverse();draw();checkMission();}\r\ndocument.getElementById(''check'').onclick=()=>{testing=sel;draw();clearTimeout(testT);testT=setTimeout(()=>{testing=-1;draw();},1400);};\r\ndocument.getElementById(''auto'').onclick=()=>{let a=1;FX.forEach(fx=>{fx.addr=a;a+=foot(fx);});update();};\r\n// missões\r\nconst M=[\r\n {t:''Toda fixture no endereço 1 se sobrepõe. <b>Endereça as 4 sem nenhum conflito</b> (mapa todo sem vermelho).'',ok:()=>!anyConflict()},\r\n {t:''Coloque o <b>Moving Spot no modo 24ch</b> e re-endereça tudo em sequência sem sobrepor.'',ok:()=>FX[3].mode===1&&!anyConflict()},\r\n {t:''Faça o <b>PAR LED 1 e o PAR LED 2 no MESMO endereço</b> de propósito (clones que reagem juntos) — e mantenha os movings sem conflito com eles.'',ok:()=>FX[0].addr===FX[1].addr && FX[0].mode===FX[1].mode && !overlapMovings()},\r\n {t:''Volte a um patch limpo: use “Auto-endereçar” e confira no <b>channel check</b>.'',ok:()=>!anyConflict()&&sequential()},\r\n];\r\nfunction overlapMovings(){const set=[2,3];return !set.some(i=>{const a1=FX[i].addr,a2=a1+foot(FX[i])-1;return [0,1].some(j=>{const b1=FX[j].addr,b2=b1+foot(FX[j])-1;return a1<=b2&&b1<=a2;})|| (i===2&&(function(){const b1=FX[3].addr,b2=b1+foot(FX[3])-1;return a1<=b2&&b1<=a2;})());});}\r\nfunction sequential(){let a=1;for(const fx of FX){if(fx.addr!==a)return false;a+=foot(fx);}return true;}\r\nlet mi=0;\r\nfunction drawMission(){document.getElementById(''mission'').innerHTML=`<div><b>Missão ${mi+1}/${M.length}:</b> ${M[mi].t}</div><div class=\"mrow\"><span class=\"dot\" id=\"mdot\"></span><span id=\"mstat\">…</span></div>`;}\r\nfunction checkMission(){const dot=document.getElementById(''mdot'');if(!dot)return;let ok=false;try{ok=M[mi].ok();}catch(e){}if(ok){dot.classList.add(''ok'');document.getElementById(''mstat'').textContent=''✓ Correto! Próxima missão.'';}else{dot.classList.remove(''ok'');document.getElementById(''mstat'').textContent=''Ajuste os endereços…'';}}\r\ndocument.getElementById(''next'').onclick=()=>{mi=(mi+1)%M.length;drawMission();update();};\r\nfunction fit(){const DW=1010,DH=625;const vw=innerWidth,vh=innerHeight;const scrH=(window.screen&&screen.height)||vh;const iframeTaller=vh>scrH+8;const visH=Math.min(vh,scrH);const headerAllow=iframeTaller?84:(vh>700?24:6);const effVh=Math.max(240,visH-headerAllow);const z=Math.min(vw/DW,effVh/DH);document.getElementById(''console'').style.zoom=z;requestAnimationFrame(sizeCanvas);}\r\naddEventListener(''resize'',fit);buildFixtures();paintUniverse();drawMission();fit();setTimeout(fit,60);\r\n</script></body></html>\r\n"}]'::jsonb);

-- AULA 7 [M2.3]: Cabos e conectores de luz: DMX, energia e a linha bem feita
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('10c00000-b551-4c00-9000-0000000b0007','10c00000-b551-4c00-9000-0000000000a2','Cabos e conectores de luz: DMX, energia e a linha bem feita','texto','<p><strong>Uma linha de luz mal feita transforma um show pronto num pesadelo de fixtures piscando.</strong> Cabo é o que leva o comando da mesa até cada refletor e a energia até cada fixture. Nesta aula você aprende a diferença entre cabo de dados e cabo de força, por que o cabo errado dá erro "fantasma", e como fechar uma linha DMX que simplesmente funciona.</p>

<h3>Cabo DMX: o cabo de dados</h3>
<p>O DMX é o "idioma" que a mesa usa para falar com as fixtures. O cabo tem que ser feito para isso: <strong>blindado</strong> (para rejeitar interferência) e com <strong>impedância de 120Ω</strong>. O conector é XLR — parecido com o de microfone, mas o serviço é outro.</p>
<ul>
<li><strong>XLR de 3 pinos:</strong> o mais comum no Brasil. Simples e direto.</li>
<li><strong>XLR de 5 pinos:</strong> o padrão original do DMX. Os pinos 4 e 5 quase nunca são usados (seriam um segundo canal de dados).</li>
<li><strong>Adaptadores 3↔5 pinos:</strong> existem para casar mesa e fixture de padrões diferentes. Ande sempre com um par na maleta.</li>
</ul>

<figure style="margin:16px 0;text-align:center"><img src="https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/img-luz-basico/conectores-dmx.jpg" alt="Conectores DMX lado a lado: XLR de 3 pinos (macho e fêmea) e XLR de 5 pinos, com cabo blindado, comparados a um conector de energia travável." style="max-width:100%;border-radius:10px;border:1px solid rgba(0,0,0,.12)" /><figcaption style="font-size:12px;opacity:.75;margin-top:6px">Conectores de luz: cabo DMX com XLR de 3 e 5 pinos (dados) e o conector de energia travável (força) — dados e energia andam separados.</figcaption></figure>

<p><strong>ATENÇÃO — o erro que mais atormenta iniciante:</strong> o conector do cabo de microfone é igual ao do DMX, mas o cabo de microfone é <strong>75Ω</strong> e NÃO serve para DMX. Ele "funciona às vezes": em linha curta parece rodar, mas gera erros intermitentes — luz piscando, fixture travando, canal fantasma — e você perde horas caçando um problema que é só o cabo. Use sempre cabo DMX de verdade.</p>

<h3>Terminador: o que fecha a linha</h3>
<p>As fixtures são ligadas em cadeia (daisy chain): sai da mesa, entra na fixture 1, sai da 1 e entra na 2, e assim por diante. Na saída DMX da <strong>última fixture</strong> entra o <strong>terminador</strong>: um plug com um resistor de <strong>120Ω entre os pinos 2 e 3</strong>. Sem ele, o sinal "bate" no fim da linha e volta refletido, causando erros. Em linhas curtas às vezes roda sem terminador, mas o certo é <strong>sempre terminar</strong>.</p>

<figure style="margin:16px 0;text-align:center"><img src="https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/img-luz-basico/terminador-dmx.jpg" alt="Um plugue terminador DMX (XLR macho de 3 pinos) isolado, com a indicação de resistor de 120 ohms, encaixando na saída DMX da última fixture." style="max-width:100%;border-radius:10px;border:1px solid rgba(0,0,0,.12)" /><figcaption style="font-size:12px;opacity:.75;margin-top:6px">O terminador DMX: um plugue XLR macho com um resistor de 120Ω dentro, encaixado no DMX OUT da última fixture da linha.</figcaption></figure>

<h3>Splitter / buffer óptico DMX</h3>
<p>Quando o rig cresce, uma única linha vira problema. O <strong>splitter</strong> (ou buffer óptico) recebe uma linha DMX e a divide em vários ramos <strong>isolados</strong> — por exemplo, 1 entra e 4 ou 8 saem — cada ramo com seu próprio terminador. Vantagens: você separa o rig em braços e <strong>isola defeitos</strong>. Se um ramo tiver um cabo ruim ou fixture com pino em curto, só aquele braço cai; os outros continuam trabalhando.</p>

<h3>Energia: cabo de força é outro cabo</h3>
<p>Fixture moderna precisa de duas coisas: <strong>dados (DMX)</strong> e <strong>energia</strong>. E são cabos separados.</p>
<ul>
<li><strong>PowerCon (conector travável):</strong> o mais usado hoje. <strong>Azul = IN (entrada)</strong>, <strong>cinza = OUT (saída)</strong>. Permite LINK (daisy chain) de energia de uma fixture para a outra — mas atenção: some as correntes, você não pode passar mais fixtures do que o cabo e o disjuntor aguentam.</li>
<li><strong>IEC:</strong> a tomada padrão de aparelho (mesma do cabo de computador). Comum em fixtures menores.</li>
<li><strong>Plugues de força comuns:</strong> ainda aparecem em muito equipamento.</li>
</ul>
<p><strong>Nunca junte energia e dados</strong> correndo lado a lado por muito tempo — a força induz interferência no DMX. Leve caminhos separados; se precisar cruzar, cruze em <strong>90°</strong>.</p>

<table>
<tr><th>Cabo</th><th>Leva</th><th>Conector típico</th><th>Detalhe</th></tr>
<tr><td>DMX</td><td>Dados/comando</td><td>XLR 3 ou 5 pinos</td><td>Blindado, 120Ω, termina com terminador</td></tr>
<tr><td>Microfone</td><td>(áudio — NÃO usar em DMX)</td><td>XLR 3 pinos</td><td>75Ω, dá erro intermitente no DMX</td></tr>
<tr><td>Força</td><td>Energia</td><td>PowerCon / IEC / plugue</td><td>Separado do DMX; respeitar corrente máxima</td></tr>
</table>

<h3>Boas práticas de linha</h3>
<ul>
<li>Sobra de cabo em <strong>laçada</strong> (over-under) — nunca enrolar apertado no cotovelo nem fazer bola.</li>
<li><strong>Identifique/etiquete</strong> cada ponta: você vai agradecer na desmontagem.</li>
<li>Não pise, não esmague, não passe cadeira em cima. Cabo no chão vai com passagem/fita.</li>
<li><strong>Teste os cabos antes de subir na truss.</strong> Achar cabo ruim no solo é fácil; a 6 metros de altura, não.</li>
</ul>

<h3>Resumo prático</h3>
<p><strong>DMX de verdade (120Ω), terminador na última, força separada dos dados.</strong> Cabo de microfone no DMX é a origem clássica do "está piscando e não sei por quê". Splitter isola braços e salva o show. Testou embaixo, subiu tranquilo.</p>',16,3,true,false);
