insert into public.ai_animations (lesson_id,tipo,status,model,custo_usd,roteiro,urls) values ('10c00000-b551-4c00-9000-0000000b0009','interactive','ready','handcrafted-interactive',0,'{"titulo":"Simulador — Mesa de Luz Básica","metadata":{"titulo_aula":"Simulador — Mesa de Luz Básica","total_cenas":1,"duracao_total":0,"abordagem_didatica":"Simulador interativo — pratique movendo os controles"},"cenas":[{"numero":1,"titulo":"Simulador — Mesa de Luz Básica","modo":"widget","narracao":"Monte looks com os faders, grave cenas nos playbacks, teste o blackout e rode um chase. Complete as 5 missões.","explicacao_texto":"Monte looks com os faders, grave cenas nos playbacks, teste o blackout e rode um chase. Complete as 5 missões.","destaques":["Fader de canal e Grand Master","Gravar/chamar cenas (playbacks)","Blackout (DBO)","Chase no ritmo"]}]}'::jsonb,'[{"html":"<!doctype html><html lang=\"pt-BR\"><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no\">\r\n<title>Simulador — Mesa de Luz Básica</title>\r\n<style>\r\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\r\nhtml,body{height:100%;background:#0b0e14;color:#e7ecf3;font-family:system-ui,Segoe UI,Roboto,Arial,sans-serif;overflow:hidden}\r\nbody{display:flex;align-items:center;justify-content:center}\r\n.console{width:1020px;height:625px;background:linear-gradient(180deg,#141a26,#0c1018);border:1px solid #223049;border-radius:14px;padding:16px;display:flex;flex-direction:column;gap:11px;box-shadow:0 10px 40px #0008}\r\nh1{font-size:15px;font-weight:700;color:#cfe0ff}\r\n.sub{font-size:11.5px;color:#8aa0c2;line-height:1.4}\r\n.stage{height:150px;background:#04060a;border:1px solid #1c2740;border-radius:10px;overflow:hidden}\r\n.stage canvas{width:100%;height:100%;display:block}\r\n.mid{display:grid;grid-template-columns:1fr 300px;gap:14px;flex:1;min-height:0}\r\n.bank{display:flex;gap:8px;align-items:end;background:#0e1421;border:1px solid #22314c;border-radius:10px;padding:10px 8px}\r\n.chan{flex:1;display:flex;flex-direction:column;align-items:center;gap:5px;height:100%;justify-content:end}\r\n.track{position:relative;width:100%;max-width:30px;flex:1;min-height:120px;background:#0c1220;border:1px solid #263449;border-radius:7px;touch-action:none;cursor:pointer}\r\n.fill{position:absolute;left:0;right:0;bottom:0;border-radius:0 0 6px 6px;background:linear-gradient(0deg,#2b5aa8,#5aa0ff)}\r\n.knob{position:absolute;left:-2px;right:-2px;height:12px;background:#e7ecf3;border-radius:4px}\r\n.clbl{font-size:10px;color:#9fb4d6;font-weight:700}.cval{font-size:9.5px;color:#7f96bb;font-variant-numeric:tabular-nums}\r\n.side{display:flex;flex-direction:column;gap:9px;min-width:0}\r\n.gm{display:flex;gap:9px;background:#0e1421;border:1px solid #22314c;border-radius:10px;padding:9px}\r\n.gm .track{min-height:0;height:70px;max-width:26px}\r\n.pb{display:grid;grid-template-columns:repeat(4,1fr);gap:7px}\r\n.pbtn{background:#141d30;border:1px solid #2a3a58;border-radius:8px;padding:7px 3px;text-align:center;cursor:pointer}\r\n.pbtn.act{border-color:#39d98a;box-shadow:0 0 0 1px #39d98a}\r\n.pbtn .t{font-size:10px;font-weight:700}.pbtn .s{font-size:9px;color:#8298bd}\r\n.row{display:flex;gap:7px;flex-wrap:wrap}\r\nbutton{background:#1b2740;color:#dce7fb;border:1px solid #33507f;border-radius:8px;padding:7px 9px;font-size:11px;font-weight:600;cursor:pointer}\r\nbutton:hover{background:#233459}button.on{background:#7a2740;border-color:#c04d6e}button.rec{background:#8a6a1e;border-color:#caa23a}\r\n.mission{background:#0e1626;border:1px solid #24406e;border-radius:10px;padding:8px 10px;font-size:11px;line-height:1.4}\r\n.mrow{display:flex;align-items:center;gap:7px;margin-top:3px}.dot{width:12px;height:12px;border-radius:50%;border:2px solid #37507a;flex:none}.dot.ok{background:#39d98a;border-color:#39d98a}\r\n</style></head>\r\n<body>\r\n<div class=\"console\" id=\"console\">\r\n  <div><h1>Mesa de Luz — Canais, Cenas e Chase</h1>\r\n    <div class=\"sub\">Suba os <b>faders de canal</b> para montar um look. <b>REC</b> + um playback grava a cena. O <b>Grand Master</b> limita tudo; <b>Blackout</b> apaga; <b>Chase</b> alterna cenas no ritmo.</div></div>\r\n  <div class=\"stage\"><canvas id=\"cv\"></canvas></div>\r\n  <div class=\"mid\">\r\n    <div class=\"bank\" id=\"bank\"></div>\r\n    <div class=\"side\">\r\n      <div class=\"gm\">\r\n        <div class=\"chan\" style=\"max-width:34px\"><div class=\"cval\" id=\"gmval\">100</div><div class=\"track\" id=\"gmtrack\" style=\"width:26px\"><div class=\"fill\" style=\"height:100%;background:linear-gradient(0deg,#8a6a1e,#e0b93a)\"></div><div class=\"knob\" style=\"bottom:100%\"></div></div><div class=\"clbl\">GM</div></div>\r\n        <div style=\"display:flex;flex-direction:column;gap:6px;justify-content:center;flex:1\">\r\n          <button id=\"blackout\">BLACKOUT (DBO)</button>\r\n          <button id=\"rec\" class=\"\">REC — gravar cena</button>\r\n          <button id=\"chase\">▶ CHASE</button>\r\n        </div>\r\n      </div>\r\n      <div><div class=\"clbl\" style=\"margin-bottom:5px\">PLAYBACKS / SUBMASTERS</div><div class=\"pb\" id=\"pb\"></div></div>\r\n      <div class=\"mission\" id=\"mission\"></div>\r\n      <div class=\"row\"><button id=\"next\">Próxima missão ▸</button><button id=\"clear\">Zerar canais</button></div>\r\n    </div>\r\n  </div>\r\n</div>\r\n<script>\r\nconst NCH=8;\r\nconst ch=new Array(NCH).fill(0);      // 0..255\r\nlet gm=255, blackout=false, recMode=false, chaseOn=false, chaseIdx=0, chaseT=null;\r\nconst scenes=[null,null,null,null];   // 4 playbacks\r\nlet activePB=-1;\r\nconst COLORS=[''#ff5a5a'',''#ff9a3a'',''#ffe08a'',''#48e06a'',''#3ad1c2'',''#4d8bff'',''#9b6bff'',''#ff6bd0''];\r\n// bank\r\nconst bank=document.getElementById(''bank'');\r\nfor(let i=0;i<NCH;i++){const el=document.createElement(''div'');el.className=''chan'';\r\n el.innerHTML=`<div class=\"cval\" data-v>0</div><div class=\"track\" data-i=\"${i}\"><div class=\"fill\" data-fill style=\"height:0%\"></div><div class=\"knob\" data-knob style=\"bottom:0%\"></div></div><div class=\"clbl\" style=\"color:${COLORS[i]}\">C${i+1}</div>`;\r\n bank.appendChild(el);const track=el.querySelector(''.track'');\r\n const set=cy=>{const r=track.getBoundingClientRect();let p=1-(cy-r.top)/r.height;p=Math.max(0,Math.min(1,p));ch[i]=Math.round(p*255);activePB=-1;render();};\r\n track.addEventListener(''pointerdown'',e=>{try{track.setPointerCapture(e.pointerId);}catch(_){}set(e.clientY);});\r\n track.addEventListener(''pointermove'',e=>{if(e.buttons)set(e.clientY);});\r\n}\r\n// grand master fader\r\nconst gmt=document.getElementById(''gmtrack'');\r\nconst setGM=cy=>{const r=gmt.getBoundingClientRect();let p=1-(cy-r.top)/r.height;p=Math.max(0,Math.min(1,p));gm=Math.round(p*255);render();};\r\ngmt.addEventListener(''pointerdown'',e=>{try{gmt.setPointerCapture(e.pointerId);}catch(_){}setGM(e.clientY);});\r\ngmt.addEventListener(''pointermove'',e=>{if(e.buttons)setGM(e.clientY);});\r\n// playbacks\r\nconst pb=document.getElementById(''pb'');\r\nfor(let i=0;i<4;i++){const el=document.createElement(''div'');el.className=''pbtn'';el.dataset.i=i;\r\n el.innerHTML=`<div class=\"t\">PB ${i+1}</div><div class=\"s\" data-s>vazio</div>`;\r\n el.onclick=()=>{if(recMode){scenes[i]=ch.slice();recMode=false;document.getElementById(''rec'').classList.remove(''rec'');render();}\r\n   else if(scenes[i]){for(let k=0;k<NCH;k++)ch[k]=scenes[i][k];activePB=i;chaseOn=false;stopChase();render();}};\r\n pb.appendChild(el);}\r\n// buttons\r\ndocument.getElementById(''blackout'').onclick=e=>{blackout=!blackout;e.target.classList.toggle(''on'',blackout);render();};\r\ndocument.getElementById(''rec'').onclick=e=>{recMode=!recMode;e.target.classList.toggle(''rec'',recMode);};\r\ndocument.getElementById(''clear'').onclick=()=>{for(let i=0;i<NCH;i++)ch[i]=0;activePB=-1;render();};\r\ndocument.getElementById(''chase'').onclick=e=>{chaseOn=!chaseOn;e.target.classList.toggle(''on'',chaseOn);if(chaseOn)startChase();else stopChase();render();};\r\nfunction startChase(){stopChase();const have=scenes.filter(Boolean);if(have.length<2){/* usa canais isolados */}\r\n chaseT=setInterval(()=>{const filled=scenes.map((s,i)=>s?i:-1).filter(i=>i>=0);\r\n   if(filled.length>=2){chaseIdx=(chaseIdx+1)%filled.length;const s=scenes[filled[chaseIdx]];for(let k=0;k<NCH;k++)ch[k]=s[k];}\r\n   else{chaseIdx=(chaseIdx+1)%NCH;for(let k=0;k<NCH;k++)ch[k]=(k===chaseIdx?255:0);}\r\n   render();},420);}\r\nfunction stopChase(){if(chaseT){clearInterval(chaseT);chaseT=null;}}\r\n// render\r\nconst cv=document.getElementById(''cv'');const ctx=cv.getContext(''2d'');\r\nfunction sizeCanvas(){const r=cv.getBoundingClientRect();const dpr=Math.min(2,devicePixelRatio||1);cv.width=r.width*dpr;cv.height=r.height*dpr;ctx.setTransform(dpr,0,0,dpr,0,0);drawStage();}\r\nfunction out(i){return blackout?0:Math.round(ch[i]*(gm/255));}\r\nfunction drawStage(){const r=cv.getBoundingClientRect();const W=r.width,H=r.height;ctx.clearRect(0,0,W,H);ctx.fillStyle=''#04060a'';ctx.fillRect(0,0,W,H);\r\n const gap=W/(NCH+1);\r\n for(let i=0;i<NCH;i++){const x=gap*(i+1);const v=out(i)/255;\r\n  // fixture\r\n  ctx.fillStyle=''#161b26'';ctx.fillRect(x-13,8,26,10);\r\n  if(v>0.01){const bg=ctx.createLinearGradient(0,18,0,H);bg.addColorStop(0,hex(COLORS[i],Math.min(0.9,v)));bg.addColorStop(1,hex(COLORS[i],0));\r\n   ctx.beginPath();ctx.moveTo(x-6,18);ctx.lineTo(x-gap*0.42,H);ctx.lineTo(x+gap*0.42,H);ctx.lineTo(x+6,18);ctx.closePath();ctx.fillStyle=bg;ctx.fill();\r\n   ctx.fillStyle=hex(COLORS[i],v);ctx.beginPath();ctx.arc(x,14,4,0,7);ctx.fill();}\r\n }\r\n ctx.fillStyle=''#7f96bb'';ctx.font=''10px system-ui'';ctx.textAlign=''left'';\r\n let tag=blackout?''BLACKOUT'':(chaseOn?''CHASE rodando'':(activePB>=0?(''Playback ''+(activePB+1)):''ao vivo''));\r\n ctx.fillText(''Saída DMX · ''+tag+'' · GM ''+Math.round(gm/255*100)+''%'',10,H-10);\r\n}\r\nfunction hex(h,a){const c=h.replace(''#'','''');return `rgba(${parseInt(c.substr(0,2),16)},${parseInt(c.substr(2,2),16)},${parseInt(c.substr(4,2),16)},${a})`;}\r\nfunction render(){for(let i=0;i<NCH;i++){const el=bank.children[i];const p=ch[i]/255*100;el.querySelector(''[data-fill]'').style.height=p+''%'';el.querySelector(''[data-knob]'').style.bottom=p+''%'';el.querySelector(''[data-v]'').textContent=Math.round(ch[i]/255*100);}\r\n document.getElementById(''gmval'').textContent=Math.round(gm/255*100);gmt.querySelector(''.fill'').style.height=(gm/255*100)+''%'';gmt.querySelector(''.knob'').style.bottom=(gm/255*100)+''%'';\r\n pb.querySelectorAll(''.pbtn'').forEach((el,i)=>{el.classList.toggle(''act'',activePB===i);el.querySelector(''[data-s]'').textContent=scenes[i]?''gravada'':''vazio'';});\r\n drawStage();check();}\r\n// missões\r\nconst M=[\r\n {t:''Monte um look (suba ao menos 3 canais) e grave em <b>PB 1</b>: aperte <b>REC</b> e depois <b>PB 1</b>.'',ok:()=>scenes[0]&&scenes[0].filter(v=>v>50).length>=3},\r\n {t:''Grave um <b>segundo look diferente</b> em <b>PB 2</b>.'',ok:()=>scenes[0]&&scenes[1]&&JSON.stringify(scenes[0])!==JSON.stringify(scenes[1])},\r\n {t:''Teste o <b>Blackout</b>: apague tudo instantâneo com o botão DBO.'',ok:()=>blackout===true},\r\n {t:''Rode um <b>Chase</b> (precisa de 2 playbacks gravados) e veja as cenas alternando.'',ok:()=>chaseOn&&scenes.filter(Boolean).length>=2},\r\n {t:''Erro clássico: com o <b>Grand Master abaixado</b> nada acende. Deixe o GM em 100% de novo.'',ok:()=>gm>=250&&!blackout},\r\n];\r\nlet mi=0;\r\nfunction drawMission(){document.getElementById(''mission'').innerHTML=`<div><b>Missão ${mi+1}/${M.length}:</b> ${M[mi].t}</div><div class=\"mrow\"><span class=\"dot\" id=\"mdot\"></span><span id=\"mstat\">…</span></div>`;}\r\nfunction check(){const dot=document.getElementById(''mdot'');if(!dot)return;let ok=false;try{ok=M[mi].ok();}catch(e){}if(ok){dot.classList.add(''ok'');document.getElementById(''mstat'').textContent=''✓ Feito! Próxima missão.'';}else{dot.classList.remove(''ok'');document.getElementById(''mstat'').textContent=''…'';}}\r\ndocument.getElementById(''next'').onclick=()=>{mi=(mi+1)%M.length;drawMission();render();};\r\nfunction fit(){const DW=1020,DH=625;const vw=innerWidth,vh=innerHeight;const scrH=(window.screen&&screen.height)||vh;const iframeTaller=vh>scrH+8;const visH=Math.min(vh,scrH);const headerAllow=iframeTaller?84:(vh>700?24:6);const effVh=Math.max(240,visH-headerAllow);const z=Math.min(vw/DW,effVh/DH);document.getElementById(''console'').style.zoom=z;requestAnimationFrame(sizeCanvas);}\r\naddEventListener(''resize'',fit);drawMission();render();fit();setTimeout(fit,60);\r\n</script></body></html>\r\n"}]'::jsonb);

-- AULA 10 [M3.2]: Segurança: elétrica, altura, rigging e a truss
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('10c00000-b551-4c00-9000-0000000b0010','10c00000-b551-4c00-9000-0000000000a3','Segurança: elétrica, altura, rigging e a truss','texto','<p><strong>Segurança não é burocracia: é o que separa um show de uma tragédia.</strong> Você vai trabalhar com peso suspenso sobre a cabeça das pessoas e com energia elétrica de alta corrente. Uma fixture caindo mata; um curto num palco molhado mata. Esta aula é a mais séria do curso — leia como quem quer voltar para casa inteiro.</p>

<figure style="margin:16px 0;text-align:center"><img src="https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/img-luz-basico/truss-clamp-safety.jpg" alt="Detalhe de uma fixture pendurada numa truss de alumínio por uma garra (clamp) e presa também por um cabo de aço de segurança." style="max-width:100%;border-radius:10px;border:1px solid rgba(0,0,0,.12)" /><figcaption style="font-size:12px;opacity:.75;margin-top:6px">Toda fixture na truss leva a garra (clamp) firme E o cabo de aço de segurança — se a garra falhar, o safety segura. Fixture caindo mata.</figcaption></figure>

<h3>Prendeu, travou, segurou: clamp e safety</h3>
<p><strong>Toda fixture pendurada leva cabo de aço de segurança (safety/steel)</strong> preso na estrutura, além da garra. O safety é a redundância: se a garra abrir ou o parafuso soltar, o cabo de aço segura a fixture antes que ela caia. Nunca pendure nada sem ele — nunca.</p>
<ul>
<li><strong>Clamp / garra:</strong> é o que prende a fixture na truss. Aperte firme e feche a trava/parafuso de segurança. Confira o quick-lock/manopla antes de largar o peso.</li>
<li><strong>Cabo de aço:</strong> passe por dentro da alça da fixture e feche na estrutura. Ele deve estar com a menor folga possível — quanto mais curto o tranco, menor o impacto se algo ceder.</li>
</ul>

<figure style="margin:16px 0;text-align:center"><img src="https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/img-luz-basico/talha-truss.jpg" alt="Truss de alumínio sendo içada por uma talha/moitão de corrente, com as luzes montadas, numa montagem de palco." style="max-width:100%;border-radius:10px;border:1px solid rgba(0,0,0,.12)" /><figcaption style="font-size:12px;opacity:.75;margin-top:6px">A truss de alumínio com as luzes é içada por talhas (moitão de corrente) — respeite sempre o limite de carga (kg) da estrutura e da talha, e ninguém passa embaixo.</figcaption></figure>

<h3>Truss, talha e carga</h3>
<p><strong>Cada truss e cada talha tem um limite de peso (kg) — e você NUNCA ultrapassa.</strong> Some o peso de todas as fixtures, cabos e acessórios que vão na estrutura e compare com a capacidade especificada. Na dúvida, sobra menos peso, não mais.</p>
<ul>
<li><strong>Truss (treliça de alumínio):</strong> tem carga máxima que depende do vão e de como está apoiada. Distribua o peso ao longo dela, não concentre tudo no meio.</li>
<li><strong>Talha / guincho / moitão:</strong> içamento com trava. Uma vez içada, a carga fica travada mecanicamente — e ninguém, jamais, passa embaixo de carga suspensa.</li>
</ul>

<h3>As normas (NRs) que regem o trabalho</h3>
<ul>
<li><strong>NR10 — eletricidade:</strong> segurança em instalações e serviços com energia. Quem mexe em energia precisa de treinamento formal.</li>
<li><strong>NR35 — trabalho em altura:</strong> tudo acima de 2 m exige cinto/talabarte, ponto de ancoragem e treinamento. Subir na truss é trabalho em altura.</li>
<li><strong>NR12 — máquinas:</strong> cobre talhas, motores e equipamentos de içamento.</li>
</ul>
<p>Resumindo: <strong>trabalhar em altura e com energia exige treinamento e EPI.</strong> Não é opcional e não é frescura.</p>

<h3>EPI: o que vestir</h3>
<ul>
<li><strong>Capacete</strong> na montagem — coisa cai de cima.</li>
<li><strong>Luva</strong> para manusear estrutura, cabo de aço e fixtures quentes.</li>
<li><strong>Calçado</strong> fechado e resistente.</li>
<li><strong>Cinto/talabarte</strong> sempre que estiver em altura, ancorado em ponto firme.</li>
</ul>

<h3>Elétrica: as regras que não se quebram</h3>
<ul>
<li><strong>Aterramento sempre.</strong> Sem terra, um defeito coloca a carcaça viva e quem tocar leva o choque.</li>
<li><strong>Não sobrecarregue o circuito</strong> (você viu isso na aula de potência): some as cargas e respeite o disjuntor.</li>
<li><strong>Cabo de bitola certa</strong> para a corrente — cabo fino esquenta e pega fogo.</li>
<li><strong>Não mexa em energia com o circuito ligado.</strong> Desligue e confira.</li>
<li><strong>Nunca "gato"/gambiarra.</strong> Emenda torta em palco é acidente marcado.</li>
<li><strong>Chuva e umidade:</strong> em palco externo, respeite o grau de proteção (IP) das fixtures e proteja a distro. Água e energia não se misturam.</li>
</ul>

<h3>Cabos no chão</h3>
<p>Passe os cabos por onde <strong>não há circulação de pessoas</strong>. Fixe com fita/gaffer e, nas passagens de público, use canaleta/passa-cabo. Cabo solto é risco duplo: alguém tropeça e, ao tropeçar, pode puxar uma fixture ou derrubar a estrutura.</p>

<h3>Resumo prático</h3>
<p><strong>Na dúvida sobre estrutura ou energia, pare e chame o responsável.</strong> Safety em toda fixture, carga sempre abaixo do limite, ninguém embaixo de peso suspenso, EPI na montagem e na altura. Segurança vem antes do show — sempre.</p>',18,2,true,false);
